import React, { useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import {
    Calendar,
    Users,
    Search,
    MapPin,
    ChevronDown,
    Building2 // Icon for "1 room" if needed, using generic for now
} from 'lucide-react';
import { format, addDays } from 'date-fns';
import { useBooking } from '../../context/BookingContext';
import GuestDetailsModal from './GuestDetailsModal';

const SearchWidget = ({ className = '' }) => {
    const navigate = useNavigate();
    const { setDates, setGuests, setRooms } = useBooking();

    const today = new Date();
    const tomorrow = addDays(today, 1);

    // State for inputs
    const [location, setLocation] = useState('Mantralayam');
    const [checkIn, setCheckIn] = useState(format(today, 'yyyy-MM-dd'));
    const [checkOut, setCheckOut] = useState(format(tomorrow, 'yyyy-MM-dd'));
    const [rooms, setRoomValue] = useState(1);
    const [guests, setGuestValue] = useState(2);

    // Refs for date inputs to trigger picker programmatically
    const checkInRef = useRef(null);
    const checkOutRef = useRef(null);

    // UI States
    const [isGuestModalOpen, setIsGuestModalOpen] = useState(false);

    const handleSearch = () => {
        setDates(new Date(checkIn), new Date(checkOut));
        setGuests(guests);
        setRooms(rooms);

        const params = new URLSearchParams();
        params.append('location', location);
        params.append('checkIn', checkIn);
        params.append('checkOut', checkOut);
        params.append('guests', guests);
        params.append('rooms', rooms);

        navigate(`/lodges?${params.toString()}`);
    };

    return (
        <div className={`w-full max-w-sm mx-auto bg-white rounded-3xl shadow-xl overflow-hidden p-3 sm:p-4 ${className}`}>
            <div className="space-y-2 sm:space-y-3">
                {/* Location Input */}
                <div className="relative group">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 w-4 h-4 sm:w-5 sm:h-5 pointer-events-none" />
                    <input
                        type="text"
                        value={location}
                        onChange={(e) => setLocation(e.target.value)}
                        className="w-full bg-blue-50/50 hover:bg-blue-50 focus:bg-white border-none py-2.5 sm:py-3.5 pl-12 pr-12 rounded-full text-gray-900 font-medium placeholder-gray-500 focus:ring-2 focus:ring-blue-500/20 transition-all text-sm sm:text-base"
                        placeholder="Search location"
                    />
                    <div className="absolute right-2 top-1/2 -translate-y-1/2 p-2 rounded-full hover:bg-black/5 cursor-pointer transition-colors">
                        <MapPin className="text-gray-700 w-5 h-5" />
                    </div>
                </div>

                {/* Date Inputs - Row of pills */}
                <div className="flex gap-2 sm:gap-3">
                    <div
                        onClick={() => checkInRef.current?.showPicker()}
                        className="flex-1 bg-blue-50/50 hover:bg-blue-50 rounded-2xl p-2.5 sm:p-3 flex items-center gap-1.5 sm:gap-2 transition-colors cursor-pointer relative"
                    >
                        <Calendar className="w-4 h-4 sm:w-5 sm:h-5 text-gray-700" />
                        <span className="text-xs sm:text-sm font-medium text-gray-700 truncate">{format(new Date(checkIn), 'EEE, MMM d')}</span>
                        <input
                            ref={checkInRef}
                            type="date"
                            value={checkIn}
                            min={format(today, 'yyyy-MM-dd')}
                            onChange={(e) => {
                                setCheckIn(e.target.value);
                                if (new Date(e.target.value) >= new Date(checkOut)) {
                                    setCheckOut(format(addDays(new Date(e.target.value), 1), 'yyyy-MM-dd'));
                                }
                            }}
                            className="absolute inset-0 opacity-0 cursor-pointer z-10"
                        />
                    </div>
                    <div
                        onClick={() => checkOutRef.current?.showPicker()}
                        className="flex-1 bg-blue-50/50 hover:bg-blue-50 rounded-2xl p-2.5 sm:p-3 flex items-center gap-1.5 sm:gap-2 transition-colors cursor-pointer relative"
                    >
                        <Calendar className="w-4 h-4 sm:w-5 sm:h-5 text-gray-700" />
                        <span className="text-xs sm:text-sm font-medium text-gray-700 truncate">{format(new Date(checkOut), 'EEE, MMM d')}</span>
                        <input
                            ref={checkOutRef}
                            type="date"
                            value={checkOut}
                            min={format(addDays(new Date(checkIn), 1), 'yyyy-MM-dd')}
                            onChange={(e) => setCheckOut(e.target.value)}
                            className="absolute inset-0 opacity-0 cursor-pointer z-10"
                        />
                    </div>
                </div>

                {/* Guests/Rooms Input */}
                <button
                    onClick={() => setIsGuestModalOpen(true)}
                    className="w-full bg-blue-50/50 hover:bg-blue-50 rounded-2xl p-2.5 sm:p-3.5 flex items-center gap-3 transition-colors text-left"
                >
                    <Users className="w-4 h-4 sm:w-5 sm:h-5 text-gray-700" />
                    <span className="text-gray-900 font-medium text-xs sm:text-sm">
                        {rooms} {rooms === 1 ? 'room' : 'rooms'} {guests} {guests === 1 ? 'guest' : 'guests'}
                    </span>
                </button>

                {/* Actions Row */}
                <div className="flex items-center gap-2 sm:gap-3 mt-1 sm:mt-2">
                    <button className="w-10 h-10 sm:w-12 sm:h-12 rounded-full border border-gray-200 flex items-center justify-center text-blue-600 hover:bg-blue-50 hover:border-blue-200 transition-all shadow-sm">
                        <MapPin className="w-4 h-4 sm:w-5 sm:h-5" />
                    </button>
                    <button
                        onClick={handleSearch}
                        className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-semibold rounded-full py-2.5 sm:py-3.5 transition-all shadow-lg shadow-blue-200 active:scale-[0.98] text-sm sm:text-base"
                    >
                        Search
                    </button>
                </div>
            </div>

            {/* Guest Details Modal */}
            <GuestDetailsModal
                isOpen={isGuestModalOpen}
                onClose={() => setIsGuestModalOpen(false)}
                rooms={rooms}
                setRooms={setRoomValue}
                guests={guests}
                setGuests={setGuestValue}
            />
        </div>
    );
};

export default SearchWidget;

import React from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import {
    Star,
    MapPin,
    Phone,
    MessageCircle,
    Wifi,
    Car,
    Droplets,
    Wind,
    Zap
} from 'lucide-react';
import { getImageUrl } from '../../services/api';

const LodgeCard = ({ lodge, index = 0 }) => {
    const {
        id,
        name,
        slug,
        images = [],
        distance,
        distanceType,
        rating,
        reviewCount,
        priceStarting,
        availability,
        amenities = [],
        rooms = []
    } = lodge;

    // Fallback image if no images available
    const rawImage = images.length > 0 ? images[0] : null;
    const displayImage = getImageUrl(rawImage);

    // Calculate availability from rooms if rooms exist
    const calculateAvailability = () => {
        if (rooms && rooms.length > 0) {
            const totalAvailable = rooms.reduce((sum, room) => sum + (room.available || 0), 0);
            if (totalAvailable === 0) return 'full';
            if (totalAvailable <= 5) return 'limited';
            return 'available';
        }
        return availability || 'available';
    };

    const computedAvailability = calculateAvailability();

    const getAvailabilityBadge = () => {
        switch (computedAvailability) {
            case 'available':
                return <span className="badge-available">Available</span>;
            case 'limited':
                return <span className="badge-limited">Limited Rooms</span>;
            case 'full':
                return <span className="badge-full">Fully Booked</span>;
            default:
                return null;
        }
    };

    const getDistanceBadge = () => {
        return (
            <span className={`badge-distance ${distanceType === 'walkable' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'}`}>
                <MapPin size={12} className="mr-1" />
                {distance} • {distanceType === 'walkable' ? 'Walking distance' : 'Auto distance'}
            </span>
        );
    };

    const amenityIcons = {
        wifi: Wifi,
        parking: Car,
        hotWater: Droplets,
        ac: Wind,
        powerBackup: Zap
    };

    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4, delay: index * 0.1 }}
            className="group relative bg-white rounded-2xl shadow-sm hover:shadow-xl transition-all duration-300 border border-gray-100 overflow-hidden block h-full flex flex-col"
        >
            <Link to={`/lodge/${slug}`} className="absolute inset-0 z-10">
                <span className="sr-only">View {name}</span>
            </Link>
            {/* Image Section */}
            <div className="relative aspect-[4/3] overflow-hidden">
                <img
                    src={displayImage}
                    alt={name}
                    className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
                    onError={(e) => {
                        e.target.onerror = null;
                        e.target.src = 'https://via.placeholder.com/400x300?text=No+Image';
                    }}
                />

                {/* Overlays */}
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-60" />

                {/* Top Badges */}
                <div className="absolute top-3 left-3 flex flex-col gap-2">
                    {getAvailabilityBadge()}
                    {rating >= 4.5 && (
                        <div className="flex items-center gap-1 bg-yellow-400 text-yellow-950 px-2 py-1 rounded-full text-[10px] font-bold shadow-md">
                            <Star size={10} className="fill-current" />
                            Trusted by Devotees
                        </div>
                    )}
                </div>

                <div className="absolute top-3 right-3">
                    {getDistanceBadge()}
                </div>
            </div>

            {/* Content Section */}
            <div className="p-4">
                {/* Title */}
                <div>
                    <h3 className="text-lg font-bold text-gray-900 mb-2 group-hover:text-primary-600 transition-colors line-clamp-1">
                        {name}
                    </h3>
                </div>

                {/* Rating & Reviews */}
                <div className="flex items-center gap-2 mb-3">
                    <div className="flex items-center gap-1 bg-green-600 text-white px-1.5 py-0.5 rounded text-xs font-bold">
                        <span>{rating}</span>
                        <Star size={10} className="fill-current" />
                    </div>
                    <span className="text-xs text-gray-500 font-medium">
                        ({reviewCount} reviews)
                    </span>
                </div>

                {/* Amenities */}
                <div className="flex items-center gap-2 mb-4">
                    <div className="flex -space-x-2">
                        {amenities.slice(0, 3).map((amenity, i) => {
                            const Icon = amenityIcons[amenity];
                            return Icon ? (
                                <div key={i} className="w-6 h-6 rounded-full bg-gray-50 border border-white flex items-center justify-center text-gray-400">
                                    <Icon size={12} />
                                </div>
                            ) : null;
                        })}
                    </div>
                    {amenities.length > 3 && (
                        <span className="text-xs text-gray-500 font-medium">
                            +{amenities.length - 3} more
                        </span>
                    )}
                </div>

                {/* Price & Action */}
                <div className="flex items-end justify-between pt-3 border-t border-dashed border-gray-100">
                    <div>
                        <p className="text-[10px] text-gray-400 font-medium uppercase tracking-wide">Starting from</p>
                        <div className="flex items-baseline gap-1">
                            <span className="text-xl font-bold text-gray-900">₹{priceStarting}</span>
                            <span className="text-xs text-gray-400">/night</span>
                        </div>
                    </div>

                    <span
                        className="px-6 py-2 bg-primary-600 group-hover:bg-primary-700 text-white text-sm font-semibold rounded-lg shadow-sm transition-colors text-center"
                    >
                        View
                    </span>
                </div>
            </div>
        </motion.div>
    );
};

export default LodgeCard;

import React, { useEffect, useMemo, useState } from 'react';
import { Star, ThumbsUp } from 'lucide-react';
import { reviewAPI } from '../../services/api';

const ReviewsSection = ({ slug }) => {
    const [reviews, setReviews] = useState([]);
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [formData, setFormData] = useState({
        name: '',
        rating: 5,
        comment: ''
    });

    useEffect(() => {
        const fetchReviews = async () => {
            try {
                setLoading(true);
                const data = await reviewAPI.getForLodge(slug);
                setReviews(Array.isArray(data) ? data : []);
            } catch (error) {
                console.error('Error fetching reviews:', error);
            } finally {
                setLoading(false);
            }
        };

        if (slug) {
            fetchReviews();
        }
    }, [slug]);

    const overall = useMemo(() => {
        if (!reviews.length) {
            return { rating: 0, count: 0 };
        }
        const total = reviews.reduce((sum, r) => sum + (r.rating || 0), 0);
        const rating = total / reviews.length;
        return { rating: Number(rating.toFixed(1)), count: reviews.length };
    }, [reviews]);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: name === 'rating' ? Number(value) : value
        }));
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!formData.name.trim() || !formData.comment.trim() || !formData.rating) {
            return;
        }

        try {
            setSubmitting(true);
            const created = await reviewAPI.create(slug, formData);
            setReviews(prev => [created, ...prev]);
            setFormData({
                name: '',
                rating: 5,
                comment: ''
            });
        } catch (error) {
            console.error('Error submitting review:', error);
            alert('Failed to submit review. Please try again.');
        } finally {
            setSubmitting(false);
        }
    };

    return (
        <div className="bg-white rounded-2xl p-6 shadow-soft mb-6">
            <h2 className="text-xl font-bold text-gray-900 mb-6 flex items-center gap-2">
                Guest Reviews
                <span className="text-sm font-normal text-gray-500">
