    // Fetch lodges from API
    useEffect(() => {
        const fetchLodges = async () => {
            try {
                setLoading(true);
                const data = await lodgeAPI.getAll();
                setLodges(data);
            } catch (error) {
                console.error('Error fetching lodges:', error);
            } finally {
                setLoading(false);
            }
        };
        fetchLodges();
    }, []);

    // Filter lodges
    const activeLodges = lodges.filter(l => !l.isBlocked);
    const availableLodges = activeLodges.filter(l => l.availability === 'available' || l.availability === 'limited');
    const walkableLodges = activeLodges.filter(l => l.distanceType === 'walkable');

    // Auto-scroll images every 4 seconds
    useEffect(() => {
        const interval = setInterval(() => {
            setCurrentSlide((prev) => (prev + 1) % heroImages.length);
        }, 4000);
        return () => clearInterval(interval);
    }, []);

    const features = [
        {
            icon: Shield,
            title: 'Verified Lodges',
            description: 'All private lodges are verified for quality and safety'
        },
        {
            icon: Clock,
