    const [lodge, setLodge] = useState(null);
    const [loading, setLoading] = useState(true);
    const [selectedRoom, setSelectedRoom] = useState(null);
    const [isFavorite, setIsFavorite] = useState(false);

    // Date picker state
    const today = new Date();
    const tomorrow = addDays(today, 1);
    const [checkIn, setCheckIn] = useState(bookingData.checkIn ? format(new Date(bookingData.checkIn), 'yyyy-MM-dd') : format(today, 'yyyy-MM-dd'));
    const [checkOut, setCheckOut] = useState(bookingData.checkOut ? format(new Date(bookingData.checkOut), 'yyyy-MM-dd') : format(tomorrow, 'yyyy-MM-dd'));
    const [guests, setGuestsValue] = useState(bookingData.guests || 1);
    const [rooms, setRoomsValue] = useState(bookingData.rooms || 1);

    // Daily price overrides: { 'YYYY-MM-DD': { 'Non-AC': price, 'AC': price, ... } }
    const [dailyPriceMap, setDailyPriceMap] = useState({});

    // Fetch lodge from API
    useEffect(() => {
        const fetchLodge = async () => {
            try {
                setLoading(true);
                const data = await lodgeAPI.getBySlug(slug);
                setLodge(data);
                selectLodge(data);
            } catch (error) {
                console.error('Error fetching lodge:', error);
            } finally {
                setLoading(false);
            }
        };
        fetchLodge();
    }, [slug]);

    // Fetch daily price overrides for every night in the stay (handles cross-month stays)
    useEffect(() => {
        if (!lodge) return;

        // Helper: format a Date as local YYYY-MM-DD (avoids UTC offset bugs in IST etc.)
        const toLocalDate = (d) => {
            const y = d.getFullYear();
            const m = String(d.getMonth() + 1).padStart(2, '0');
            const day = String(d.getDate()).padStart(2, '0');
            return `${y}-${m}-${day}`;
        };

        // Collect all unique YYYY-MM months in the stay
        const months = new Set();
        const start = new Date(checkIn + 'T00:00:00');
        const end = new Date(checkOut + 'T00:00:00');
        let cur = new Date(start);
        while (cur < end) {
            months.add(toLocalDate(cur).slice(0, 7)); // local YYYY-MM
            cur.setDate(cur.getDate() + 1);
        }

        Promise.all([...months].map(m => dailyPriceAPI.getByMonth(lodge._id, m)))
            .then(results => {
                const map = {};
                results.flat().forEach(item => {
                    if (!map[item.date]) map[item.date] = {};
                    map[item.date][item.roomType] = item.price;
                });
                setDailyPriceMap(map);
            })
            .catch(() => setDailyPriceMap({}));
    }, [lodge, checkIn, checkOut]);

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 flex items-center justify-center">
                <div className="text-center">
                    <Loader2 className="w-12 h-12 animate-spin text-primary-500 mx-auto" />
                    <p className="mt-4 text-gray-600">Loading lodge details...</p>
                </div>
            </div>
        );
    }

    if (!lodge || lodge.isBlocked) {
        return (
            <div className="min-h-screen bg-gray-50 flex items-center justify-center">
                <div className="text-center px-4">
                    <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-4">
                        <ShieldAlert size={40} className="text-red-500" />
                    </div>
                    <h1 className="text-2xl font-bold text-gray-900 mb-2">
                        {!lodge ? 'Lodge Not Found' : 'Lodge Temporarily Unavailable'}
                    </h1>
                    <p className="text-gray-600 mb-6 max-w-md mx-auto">
                        {!lodge
                            ? "The lodge you're looking for doesn't exist or has been removed."
                            : "This lodge is currently not accepting new bookings through our platform. Please check other available lodges."}
                    </p>
                    <Link to="/lodges" className="btn-primary">
                        Browse Other Lodges
                    </Link>
                </div>
            </div>
        );
    }


    // Effective price for a room on a specific date (default: check-in date for display)
    const getEffectivePrice = (room, date = checkIn) => {
        const override = dailyPriceMap[date]?.[room?.type];
        return override != null ? override : (room?.price || 0);
    };

    // Helper to check if any selected date is blocked
    const isDateRangeBlocked = () => {
        if (!lodge || !lodge.blockedDates || lodge.blockedDates.length === 0) return false;

        const start = new Date(checkIn);
        const end = new Date(checkOut);

        // Check every date from checkIn (inclusive) to checkOut (exclusive)
        for (let d = new Date(start); d < end; d.setDate(d.getDate() + 1)) {
            const dateStr = format(d, 'yyyy-MM-dd');
            if (lodge.blockedDates.includes(dateStr)) return true;
        }
        return false;
    };

    const hasBlockedDates = isDateRangeBlocked();

    // Whether the check-in date has a custom price for a room type
    const getCheckInOverridePrice = (room) => {
        const override = dailyPriceMap[checkIn]?.[room?.type];
        return override !== undefined ? override : undefined;
    };

    const handleRoomSelect = (room) => {
        setSelectedRoom(room);
        selectRoom(room);

        // Clamp guests to this room's max occupancy * rooms
        const maxGuests = (room?.maxOccupancy || 6) * rooms;
        setGuestsValue((prev) => {
            const next = Math.min(prev || 1, maxGuests);
            setGuests(next);
            return next;
        });
    };

    // Calculate total nights and per-night breakdown
    const totalNights = Math.max(1, Math.ceil((new Date(checkOut) - new Date(checkIn)) / (1000 * 60 * 60 * 24)));

    // Compute the total stay price by summing each night's effective room price
    const computeStayTotal = (room, currentRooms = rooms, currentGuests = guests) => {
        if (!room) return 0;
        const baseGuestsPerRoom = room.baseGuests || room.maxOccupancy || 1;
        const totalBaseGuests = baseGuestsPerRoom * currentRooms;
        const extraGuestFee = room.extraGuestPrice || 0;
        const extra = Math.max(0, (currentGuests || 1) - totalBaseGuests);
        let total = 0;
        const start = new Date(checkIn + 'T00:00:00');
        for (let i = 0; i < totalNights; i++) {
            const d = new Date(start);
            d.setDate(d.getDate() + i);
            // Use local date string (avoids UTC offset bugs in IST etc.)
            const y = d.getFullYear();
            const mo = String(d.getMonth() + 1).padStart(2, '0');
            const dy = String(d.getDate()).padStart(2, '0');
            const dateStr = `${y}-${mo}-${dy}`;
            const nightPrice = getEffectivePrice(room, dateStr) * currentRooms;
            total += nightPrice + extra * extraGuestFee;
        }
        return total;
    };

    const handleBookNow = () => {
        if (hasBlockedDates) {
            alert('Your selected dates include dates where the lodge is fully booked or unavailable. Please select different dates.');
            return;
        }
        if (selectedRoom) {
            const stayTotal = computeStayTotal(selectedRoom);
            // Store room with a special totalOverride so Booking.jsx can use the correct amount
            selectRoom({ ...selectedRoom, _stayTotal: stayTotal });
            setDates(new Date(checkIn), new Date(checkOut));
            setRooms(rooms);
            setGuests(guests);
            navigate('/booking');
        }
    };

    const baseGuests = selectedRoom ? (selectedRoom.baseGuests || selectedRoom.maxOccupancy || 1) : 1;
    const totalBaseGuests = baseGuests * rooms;
    const extraGuestPrice = selectedRoom?.extraGuestPrice || 0;
    const extraGuests = selectedRoom ? Math.max(0, (guests || 1) - totalBaseGuests) : 0;
    const totalPrice = selectedRoom ? computeStayTotal(selectedRoom) : 0;
    const perNightPrice = totalNights > 0 ? Math.round(totalPrice / totalNights) : 0;

    // Max guests allowed for current selected room configuration (limit to 10 rooms/60 guests)
    const maxGuestsForSelectedRoom = (selectedRoom?.maxOccupancy || 6) * rooms;

    const getGoogleMapsUrl = () => {
        return `https://www.google.com/maps/search/?api=1&query=Sri+Raghavendra+Swamy+Mutt+Mantralayam`;
    };

    return (
        <div className="min-h-screen bg-gray-50">
            {/* Top Bar - Mobile */}
            <div className="md:hidden bg-white sticky top-16 z-40 border-b border-gray-100">
                <div className="flex items-center justify-between px-4 py-3">
                    <button
                        onClick={() => navigate(-1)}
                        className="p-2 -ml-2 text-gray-600 hover:text-gray-900"
                    >
                        <ChevronLeft size={24} />
                    </button>
                    <div className="flex items-center gap-2">
                        <button
                            onClick={() => setIsFavorite(!isFavorite)}
                            className={`p-2 ${isFavorite ? 'text-red-500' : 'text-gray-600'}`}
                        >
                            <Heart size={24} fill={isFavorite ? 'currentColor' : 'none'} />
                        </button>
                        <button className="p-2 text-gray-600">
                            <Share2 size={24} />
                        </button>
                    </div>
                </div>
            </div>

            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6 md:py-10">
                {/* Breadcrumb */}
                <div className="hidden md:flex items-center gap-2 text-sm text-gray-500 mb-6">
                    <Link to="/" className="hover:text-primary-600">Home</Link>
                    <span>/</span>
                    <Link to="/lodges" className="hover:text-primary-600">Lodges</Link>
                    <span>/</span>
                    <span className="text-gray-900">{lodge.name}</span>
                </div>

                {/* Photo Gallery */}
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="mb-8"
                >
                    <PhotoGallery images={lodge.images} lodgeName={lodge.name} />
                </motion.div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    {/* Main Content */}
                    <div className="lg:col-span-2">
                        {/* Lodge Header */}
                        <motion.div
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.1 }}
                            className="bg-white rounded-2xl p-6 shadow-soft mb-6"
                        >
                            <div className="flex items-start justify-between mb-4">
                                <div>
                                    <h1 className="text-2xl md:text-3xl font-bold text-gray-900 mb-2">
                                        {lodge.name}
                                    </h1>
                                    <div className="flex items-center gap-4 text-sm text-gray-600">
                                        <span className="flex items-center gap-1">
                                            <MapPin size={16} className="text-primary-500" />
                                            {lodge.distance} from Mutt
                                        </span>
                                        <span className={`badge-distance ${lodge.distanceType === 'walkable'
                                            ? 'bg-green-100 text-green-700'
                                            : 'bg-blue-100 text-blue-700'
                                            }`}>
                                            {lodge.distanceType === 'walkable' ? 'Walking Distance' : 'Auto Distance'}
                                        </span>
                                    </div>
                                </div>
                                <div className="hidden md:flex items-center gap-2">
                                    <button
                                        onClick={() => setIsFavorite(!isFavorite)}
                                        className={`p-3 rounded-xl border-2 transition-all ${isFavorite
                                            ? 'border-red-500 text-red-500 bg-red-50'
                                            : 'border-gray-200 text-gray-600 hover:border-gray-300'
                                            }`}
                                    >
                                        <Heart size={20} fill={isFavorite ? 'currentColor' : 'none'} />
                                    </button>
                                    <button className="p-3 rounded-xl border-2 border-gray-200 text-gray-600 hover:border-gray-300 transition-colors">
                                        <Share2 size={20} />
                                    </button>
                                </div>
                            </div>

                            {/* Rating & Reviews */}
                            <div className="flex items-center gap-4 mb-4 pb-4 border-b border-gray-100">
                                <div className="flex items-center gap-2 bg-green-50 px-3 py-1.5 rounded-lg">
                                    <Star size={18} className="text-green-600 fill-green-600" />
                                    <span className="font-semibold text-green-700">{lodge.rating}</span>
                                </div>
                                <span className="text-gray-600">{lodge.reviewCount} reviews</span>
                            </div>

                            {/* Description */}
                            <p className="text-gray-600 leading-relaxed">
                                {lodge.description}
                            </p>
                        </motion.div>

                        {/* Booking Card for Mobile ONLY */}
                        <div className="block lg:hidden mb-6 bg-white rounded-2xl p-5 shadow-soft border border-gray-100">
                            <h3 className="font-bold text-gray-900 mb-4 pb-2 border-b border-gray-100">Check Availability</h3>
                            <div className="grid grid-cols-2 gap-3 mb-3">
                                <div>
                                    <label className="block text-xs font-medium text-gray-500 mb-1">Check-in</label>
                                    <div className="relative">
                                        <Calendar size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                                        <input
                                            type="date"
                                            value={checkIn}
                                            min={format(today, 'yyyy-MM-dd')}
                                            onChange={(e) => {
                                                setCheckIn(e.target.value);
                                                if (new Date(e.target.value) >= new Date(checkOut)) {
                                                    setCheckOut(format(addDays(new Date(e.target.value), 1), 'yyyy-MM-dd'));
                                                }
                                            }}
                                            className="w-full pl-9 pr-2 py-2.5 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-primary-500"
                                        />
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-xs font-medium text-gray-500 mb-1">Check-out</label>
                                    <div className="relative">
                                        <Calendar size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                                        <input
                                            type="date"
                                            value={checkOut}
                                            min={format(addDays(new Date(checkIn), 1), 'yyyy-MM-dd')}
                                            onChange={(e) => setCheckOut(e.target.value)}
                                            className="w-full pl-9 pr-2 py-2.5 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-primary-500"
                                        />
                                    </div>
                                </div>
                            </div>
                            <div className="grid grid-cols-2 gap-3">
                                <div>
                                    <label className="block text-xs font-medium text-gray-500 mb-1">Rooms</label>
                                    <div className="relative">
                                        <Building2 size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                                        <select
                                            value={rooms}
                                            onChange={(e) => {
                                                const r = Number(e.target.value);
                                                setRoomsValue(r);
                                                setRooms(r);
                                                if (selectedRoom) {
                                                    const maxG = (selectedRoom.maxOccupancy || 6) * r;
                                                    if (guests > maxG) {
                                                        setGuestsValue(maxG);
                                                        setGuests(maxG);
                                                    }
                                                }
                                            }}
                                            className="w-full pl-9 pr-4 py-2.5 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-primary-500 appearance-none"
                                        >
                                            {Array.from({ length: 10 }, (_, i) => i + 1).map(num => (
                                                <option key={num} value={num}>{num} {num === 1 ? 'Room' : 'Rooms'}</option>
                                            ))}
                                        </select>
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-xs font-medium text-gray-500 mb-1">Guests</label>
                                    <div className="relative">
                                        <Users size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                                        <select
                                            value={guests}
                                            onChange={(e) => {
                                                const value = Number(e.target.value);
                                                setGuestsValue(value);
                                                setGuests(value);
                                            }}
                                            className="w-full pl-9 pr-4 py-2.5 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-primary-500 appearance-none"
                                        >
                                            {Array.from({ length: selectedRoom ? maxGuestsForSelectedRoom : 30 }, (_, i) => i + 1).map(num => (
                                                <option key={num} value={num}>{num} {num === 1 ? 'Guest' : 'Guests'}</option>
                                            ))}
                                        </select>
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Room Types */}
                        <motion.div
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.2 }}
                            className="bg-white rounded-2xl p-6 shadow-soft mb-6"
                        >
                            <h2 className="text-xl font-bold text-gray-900 mb-4">
                                Select a Room
                            </h2>
                            <div className="space-y-4">
                                {lodge.rooms && lodge.rooms.length > 0 ? (
                                    lodge.rooms.map((room, index) => (
                                        <RoomCard
                                            key={room._id || index}
                                            room={room}
                                            overridePrice={getCheckInOverridePrice(room)}
                                            onSelect={handleRoomSelect}
                                            isSelected={selectedRoom?._id === room._id}
                                        />
                                    ))
                                ) : (
                                    <p className="text-gray-500 text-center py-4">No rooms available</p>
                                )}
                            </div>
                        </motion.div>

                        {/* Amenities */}
                        <motion.div
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.3 }}
                            className="bg-white rounded-2xl p-6 shadow-soft mb-6"
                        >
                            <h2 className="text-xl font-bold text-gray-900 mb-4">
                                Amenities
                            </h2>
                            <AmenityList amenities={lodge.amenities} />
                        </motion.div>

                        {/* Reviews */}
                        <motion.div
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.35 }}
                        >
                            <ReviewsSection slug={lodge.slug} />
                        </motion.div>

                        {/* Location */}
                        <motion.div
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.4 }}
                            className="bg-white rounded-2xl p-6 shadow-soft"
                        >
                            <h2 className="text-xl font-bold text-gray-900 mb-4">
                                Location
                            </h2>
                            <div className="aspect-video bg-gray-100 rounded-xl mb-4 overflow-hidden">
                                <iframe
                                    src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3838.8051981089815!2d77.37599!3d15.98683!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3bb5e5d7a6e5e5e5%3A0x5e5e5e5e5e5e5e5e!2sSri%20Raghavendra%20Swamy%20Mutt!5e0!3m2!1sen!2sin!4v1234567890"
                                    width="100%"
                                    height="100%"
                                    style={{ border: 0 }}
                                    allowFullScreen=""
                                    loading="lazy"
                                    referrerPolicy="no-referrer-when-downgrade"
                                    title="Lodge Location"
                                />
                            </div>
                            <p className="text-gray-600 mb-4">
                                <MapPin size={16} className="inline mr-2 text-primary-500" />
                                {lodge.address}
                            </p>
                            <a
                                href={getGoogleMapsUrl()}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="inline-flex items-center gap-2 text-primary-600 hover:text-primary-700 font-medium"
                            >
                                <Navigation size={18} />
                                Get Directions
                            </a>
                        </motion.div>
                    </div>

                    {/* Sidebar - Booking Card */}
                    <div className="hidden lg:block lg:col-span-1">
                        <div className="sticky top-24">
                            <motion.div
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                transition={{ delay: 0.2 }}
                                className="bg-white rounded-2xl p-6 shadow-elevated"
                            >
                                {/* Price */}
                                <div className="mb-6 pb-6 border-b border-gray-100">
                                    <p className="text-sm text-gray-500">Starting from</p>
                                    <div className="flex items-baseline gap-2">
                                        <span className="text-3xl font-bold text-gray-900">₹{lodge.priceStarting}</span>
                                        <span className="text-gray-500">/ night</span>
                                    </div>
                                </div>

                                {/* Date Picker */}
                                <div className="mb-6 pb-6 border-b border-gray-100">
                                    <div className="grid grid-cols-2 gap-3 mb-3">
                                        <div>
                                            <label className="block text-xs font-medium text-gray-500 mb-1">Check-in</label>
                                            <div className="relative">
                                                <Calendar size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                                                <input
                                                    type="date"
                                                    value={checkIn}
                                                    min={format(today, 'yyyy-MM-dd')}
                                                    onChange={(e) => {
                                                        setCheckIn(e.target.value);
                                                        if (new Date(e.target.value) >= new Date(checkOut)) {
                                                            setCheckOut(format(addDays(new Date(e.target.value), 1), 'yyyy-MM-dd'));
                                                        }
                                                    }}
                                                    className="w-full pl-9 pr-2 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                                />
                                            </div>
                                        </div>
                                        <div>
                                            <label className="block text-xs font-medium text-gray-500 mb-1">Check-out</label>
                                            <div className="relative">
                                                <Calendar size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                                                <input
                                                    type="date"
                                                    value={checkOut}
                                                    min={format(addDays(new Date(checkIn), 1), 'yyyy-MM-dd')}
                                                    onChange={(e) => setCheckOut(e.target.value)}
                                                    className="w-full pl-9 pr-2 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                                />
                                            </div>
                                        </div>
                                    </div>
                                    <div className="grid grid-cols-2 gap-3 mb-3">
                                        <div>
                                            <label className="block text-xs font-medium text-gray-500 mb-1">Rooms</label>
                                            <div className="relative">
                                                <Building2 size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                                                <select
                                                    value={rooms}
                                                    onChange={(e) => {
                                                        const r = Number(e.target.value);
                                                        setRoomsValue(r);
                                                        setRooms(r);
                                                        if (selectedRoom) {
                                                            const maxG = (selectedRoom.maxOccupancy || 6) * r;
                                                            if (guests > maxG) {
                                                                setGuestsValue(maxG);
                                                                setGuests(maxG);
                                                            }
                                                        }
                                                    }}
                                                    className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-primary-500 focus:border-primary-500 appearance-none"
                                                >
                                                    {Array.from({ length: 10 }, (_, i) => i + 1).map(num => (
                                                        <option key={num} value={num}>{num} {num === 1 ? 'Room' : 'Rooms'}</option>
                                                    ))}
                                                </select>
                                            </div>
                                        </div>
                                        <div>
                                            <label className="block text-xs font-medium text-gray-500 mb-1">Guests</label>
                                            <div className="relative">
                                                <Users size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                                                <select
                                                    value={guests}
                                                    onChange={(e) => {
                                                        const value = Number(e.target.value);
                                                        setGuestsValue(value);
                                                        setGuests(value);
                                                    }}
                                                    className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-primary-500 focus:border-primary-500 appearance-none"
                                                >
                                                    {Array.from({ length: selectedRoom ? maxGuestsForSelectedRoom : 30 }, (_, i) => i + 1).map(num => (
                                                        <option key={num} value={num}>{num} {num === 1 ? 'Guest' : 'Guests'}</option>
                                                    ))}
                                                </select>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="mt-2">
                                        {selectedRoom && (
                                            <p className="text-xs text-gray-600">
                                                {totalBaseGuests > 1 ? `${totalBaseGuests} guests included` : `${totalBaseGuests} guest included`} across {rooms} {rooms === 1 ? 'room' : 'rooms'}
                                                {extraGuestPrice > 0 && ` • ₹${extraGuestPrice} per extra guest`}
                                            </p>
                                        )}
                                        <p className="text-xs text-gray-500 mt-1.5 text-center">
                                            {totalNights} {totalNights === 1 ? 'night' : 'nights'}
                                        </p>
                                    </div>
                                </div>

                                {/* Selected Room */}
                                {selectedRoom && (
                                    <div className="mb-6 pb-6 border-b border-gray-100">
                                        <p className="text-sm font-medium text-gray-700 mb-2">Selected Room</p>
                                        <div className="p-3 bg-primary-50 rounded-xl">
                                            <p className="font-semibold text-gray-900 mb-1">{selectedRoom.name}</p>
                                            <div className="space-y-0.5 text-sm text-gray-700">
                                                <div className="flex justify-between">
                                                    <span>Room ({totalBaseGuests > 1 ? `${totalBaseGuests} guests` : `${totalBaseGuests} guest`}) × {rooms}</span>
                                                    <span>
                                                        {dailyPriceMap[selectedRoom.type] != null && dailyPriceMap[selectedRoom.type] !== selectedRoom.price && (
                                                            <span className="line-through text-gray-400 mr-1 text-xs">₹{selectedRoom.price * rooms}</span>
                                                        )}
                                                        ₹{getEffectivePrice(selectedRoom) * rooms}
                                                    </span>
                                                </div>
                                                {extraGuests > 0 && (
                                                    <div className="flex justify-between">
                                                        <span>Extra guests ({extraGuests})</span>
                                                        <span>₹{extraGuests * extraGuestPrice}</span>
                                                    </div>
                                                )}
                                                <div className="flex justify-between font-semibold text-primary-600 pt-1 border-t border-primary-200">
                                                    <span>Per night × {totalNights}</span>
                                                    <span>₹{totalPrice}</span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                )}

                                {/* Booking Button */}
                                {hasBlockedDates && (
                                    <div className="mb-4 p-3 bg-red-50 text-red-700 text-sm rounded-lg border border-red-100 flex items-start gap-2">
                                        <ShieldAlert size={16} className="mt-0.5 shrink-0" />
                                        <p>The lodge is fully booked or unavailable on one or more of your selected dates.</p>
                                    </div>
                                )}
                                <button
                                    onClick={handleBookNow}
                                    disabled={!selectedRoom || hasBlockedDates}
                                    className={`w-full py-4 rounded-xl text-lg font-semibold transition-all ${selectedRoom && !hasBlockedDates
                                        ? 'bg-gradient-to-r from-primary-500 to-primary-600 text-white shadow-lg hover:shadow-xl transform hover:scale-[1.02] animate-pulse hover:animate-none'
                                        : 'bg-gray-200 text-gray-500 cursor-not-allowed'
                                        }`}
                                >
                                    {hasBlockedDates ? 'Dates Unavailable' : (selectedRoom ? `Book Now • ₹${totalPrice}` : 'Select a Room to Book')}
                                </button>

                                {/* Quick Actions */}
                                <div className="grid grid-cols-2 gap-3 mt-4">
                                    <a
                                        href={`tel:${lodge.phone}`}
                                        className="btn-call py-3 text-sm justify-center"
                                    >
                                        <Phone size={18} />
                                        Call
                                    </a>
                                    <a
                                        href={`https://wa.me/${lodge.whatsapp?.replace(/[^0-9]/g, '')}?text=Hi, I want to book a room at ${lodge.name}`}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="btn-whatsapp py-3 text-sm justify-center"
                                    >
                                        <MessageCircle size={18} />
                                        WhatsApp
                                    </a>
                                </div>

                                {/* Info */}
                                <div className="mt-6 pt-6 border-t border-gray-100 space-y-3">
                                    <div className="flex items-center gap-3 text-sm text-gray-600">
                                        <Clock size={18} className="text-gray-400" />
                                        <span>Check-in: 12:00 PM | Check-out: 11:00 AM</span>
                                    </div>
                                    <div className="flex items-center gap-3 text-sm text-gray-600">
                                        <Users size={18} className="text-gray-400" />
                                        <span>ID proof required at check-in</span>
                                    </div>
                                </div>
                            </motion.div>
                        </div>
                    </div>
                </div>
            </div >

            {/* Mobile Sticky Footer */}
            <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 px-4 py-3 z-50">
                <div className="flex items-center justify-between">
                    <div>
                        <p className="text-sm text-gray-500">
                            {selectedRoom ? `${rooms}x ${selectedRoom.name} - ${totalNights} night${totalNights > 1 ? 's' : ''}` : 'Starting from'}
                        </p>
                        <p className="text-xl font-bold font-mono text-gray-900">
                            ₹{selectedRoom ? totalPrice : lodge.priceStarting}
                            {!selectedRoom && <span className="text-sm font-sans font-normal text-gray-500">/night</span>}
                        </p>
                    </div>
                    <button
                        onClick={handleBookNow}
                        disabled={!selectedRoom || hasBlockedDates}
                        className={`px-6 py-3 rounded-xl font-semibold transition-all shadow-md ${selectedRoom && !hasBlockedDates
                            ? 'bg-gradient-to-r from-primary-500 to-primary-600 text-white hover:shadow-lg active:scale-95'
                            : 'bg-gray-200 text-gray-500 cursor-not-allowed'
                            }`}
                    >
                        {hasBlockedDates ? 'Unavailable' : (selectedRoom ? 'Book Now' : 'Select Room')}
                    </button>
                </div>
            </div>

            {/* Mobile Footer Spacer */}
            < div className="md:hidden h-20" />
        </div >
    );
};

export default LodgeDetail;

import React, { useState, useMemo, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import {
    SlidersHorizontal,
    X,
    ChevronDown,
    MapPin,
    Grid3X3,
    List,
    Loader2
} from 'lucide-react';
import SearchBar from '../components/common/SearchBar';
import LodgeCard from '../components/lodge/LodgeCard';
import { lodgeAPI } from '../services/api';
import { sortOptions } from '../data/mockData';
import { useBooking } from '../context/BookingContext';
import { format, addDays } from 'date-fns';

const LodgeList = () => {
    const [searchParams] = useSearchParams();
    const { setGuests, setRooms, bookingData } = useBooking();
    const [lodges, setLodges] = useState([]);
    const [loading, setLoading] = useState(true);
    const [sortBy, setSortBy] = useState('popularity');
    const [showFilters, setShowFilters] = useState(false);
    const [showSortDropdown, setShowSortDropdown] = useState(false);
    const [viewMode, setViewMode] = useState('grid');
    const [filters, setFilters] = useState({
        distanceType: searchParams.get('distance') || '',
        priceMax: '',
        availability: '',
        amenities: []
    });

    // Fetch lodges from API
    useEffect(() => {
        const fetchLodges = async () => {
            try {
                setLoading(true);
                const data = await lodgeAPI.getAll();
                setLodges(data);
            } catch (error) {
                console.error('Error fetching lodges:', error);
            } finally {
                setLoading(false);
            }
        };
        fetchLodges();
    }, []);

    // Sync URL parameters with booking context
    useEffect(() => {
        const roomsParam = searchParams.get('rooms');
        const guestsParam = searchParams.get('guests');
        if (roomsParam) {
            setRooms(Number(roomsParam));
        }
        if (guestsParam) {
            setGuests(Number(guestsParam));
        }
    }, [searchParams, setRooms, setGuests]);

    // Apply filters and sorting locally
    const filteredLodges = useMemo(() => {
        let result = lodges.filter(lodge => !lodge.isBlocked);

        // Filter out lodges that are blocked on any of the selected dates
        const checkInParam = searchParams.get('checkIn') || bookingData?.checkIn;
        const checkOutParam = searchParams.get('checkOut') || bookingData?.checkOut;

        if (checkInParam && checkOutParam) {
            const start = new Date(checkInParam);
            const end = new Date(checkOutParam);

            // Generate array of date strings for the stay
            const stayDates = [];
            for (let d = new Date(start); d < end; d.setDate(d.getDate() + 1)) {
                stayDates.push(format(d, 'yyyy-MM-dd'));
            }

            // Keep lodge only if NONE of its blockedDates intersect with stayDates
            result = result.filter(lodge => {
                if (!lodge.blockedDates || lodge.blockedDates.length === 0) return true;
                return !stayDates.some(dateStr => lodge.blockedDates.includes(dateStr));
            });
        }

        // Filter by distance type
        if (filters.distanceType) {
            result = result.filter(lodge => lodge.distanceType === filters.distanceType);
        }

        // Filter by max price
        if (filters.priceMax) {
            result = result.filter(lodge => lodge.priceStarting <= parseInt(filters.priceMax));
        }

        // Filter by availability
        if (filters.availability && filters.availability !== 'all') {
            result = result.filter(lodge => lodge.availability === filters.availability);
        }

        // Sort
        switch (sortBy) {
            case 'priceLow':
                result.sort((a, b) => a.priceStarting - b.priceStarting);
                break;
            case 'priceHigh':
                result.sort((a, b) => b.priceStarting - a.priceStarting);
                break;
            case 'rating':
                result.sort((a, b) => b.rating - a.rating);
                break;
            case 'distance':
                result.sort((a, b) => parseInt(a.distance) - parseInt(b.distance));
                break;
            default:
                result.sort((a, b) => b.reviewCount - a.reviewCount);
        }

        return result;
    }, [lodges, filters, sortBy]);

    const handleFilterChange = (key, value) => {
        setFilters(prev => ({ ...prev, [key]: value }));
    };

    const clearFilters = () => {
        setFilters({
            distanceType: '',
            priceMax: '',
            availability: '',
            amenities: []
        });
    };

    const activeFilterCount = Object.values(filters).filter(v =>
        v && (Array.isArray(v) ? v.length > 0 : true)
    ).length;

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 flex items-center justify-center">
                <div className="text-center">
                    <Loader2 className="w-12 h-12 animate-spin text-primary-500 mx-auto" />
                    <p className="mt-4 text-gray-600">Loading lodges...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gray-50">
            {/* Header Section */}
            <div className="bg-white shadow-sm sticky top-14 sm:top-16 md:top-20 z-40">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
                    {/* Search Bar - Compact */}
                    <div className="mb-4">
                        <SearchBar variant="compact" />
                    </div>

                    {/* Filters & Sort Bar */}
                    <div className="flex items-center justify-between gap-4">
                        <div className="flex items-center gap-3">
                            {/* Filter Button */}
                            <button
                                onClick={() => setShowFilters(!showFilters)}
                                className={`flex items-center gap-2 px-4 py-2 rounded-xl border-2 transition-all ${showFilters || activeFilterCount > 0
                                    ? 'border-primary-500 bg-primary-50 text-primary-600'
                                    : 'border-gray-200 hover:border-gray-300 text-gray-700'
                                    }`}
                            >
                                <SlidersHorizontal size={18} />
                                <span className="hidden sm:inline">Filters</span>
                                {activeFilterCount > 0 && (
                                    <span className="w-5 h-5 bg-primary-500 text-white text-xs font-medium rounded-full flex items-center justify-center">
                                        {activeFilterCount}
                                    </span>
                                )}
                            </button>

                            {/* Quick Filter Pills */}
                            <div className="hidden md:flex items-center gap-2">
                                <button
                                    onClick={() => handleFilterChange('distanceType', filters.distanceType === 'walkable' ? '' : 'walkable')}
                                    className={`px-3 py-1.5 rounded-full text-sm font-medium transition-colors ${filters.distanceType === 'walkable'
                                        ? 'bg-green-100 text-green-700'
                                        : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                                        }`}
                                >
                                    <MapPin size={14} className="inline mr-1" />
                                    Walking Distance
                                </button>
                                <button
                                    onClick={() => handleFilterChange('availability', filters.availability === 'available' ? '' : 'available')}
                                    className={`px-3 py-1.5 rounded-full text-sm font-medium transition-colors ${filters.availability === 'available'
                                        ? 'bg-primary-100 text-primary-700'
                                        : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                                        }`}
                                >
                                    Available Now
                                </button>
                            </div>
                        </div>

                        <div className="flex items-center gap-3">
                            {/* Sort Dropdown */}
                            <div className="relative">
                                <button
                                    onClick={() => setShowSortDropdown(!showSortDropdown)}
                                    className="flex items-center gap-2 px-4 py-2 bg-white border-2 border-gray-200 rounded-xl text-sm font-medium text-gray-700 hover:border-gray-300 transition-colors"
                                >
                                    <span className="hidden sm:inline">Sort:</span>
                                    <span className="text-gray-900">
                                        {sortOptions.find(o => o.value === sortBy)?.label}
                                    </span>
                                    <ChevronDown size={16} className={`transition-transform ${showSortDropdown ? 'rotate-180' : ''}`} />
                                </button>

                                <AnimatePresence>
                                    {showSortDropdown && (
                                        <motion.div
                                            initial={{ opacity: 0, y: -10 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            exit={{ opacity: 0, y: -10 }}
                                            className="absolute right-0 mt-2 w-48 bg-white rounded-xl shadow-elevated border border-gray-100 overflow-hidden z-20"
                                        >
                                            {sortOptions.map((option) => (
                                                <button
                                                    key={option.value}
                                                    onClick={() => {
                                                        setSortBy(option.value);
                                                        setShowSortDropdown(false);
                                                    }}
                                                    className={`w-full px-4 py-3 text-left text-sm hover:bg-gray-50 transition-colors ${sortBy === option.value ? 'bg-primary-50 text-primary-600 font-medium' : 'text-gray-700'
                                                        }`}
                                                >
                                                    {option.label}
                                                </button>
                                            ))}
                                        </motion.div>
                                    )}
                                </AnimatePresence>
                            </div>

                            {/* View Toggle */}
                            <div className="hidden sm:flex items-center bg-gray-100 rounded-lg p-1">
                                <button
                                    onClick={() => setViewMode('grid')}
                                    className={`p-2 rounded-md transition-colors ${viewMode === 'grid' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'
                                        }`}
                                >
                                    <Grid3X3 size={18} />
                                </button>
                                <button
                                    onClick={() => setViewMode('list')}
                                    className={`p-2 rounded-md transition-colors ${viewMode === 'list' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'
                                        }`}
                                >
                                    <List size={18} />
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Filter Panel */}
            <AnimatePresence>
                {showFilters && (
                    <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        className="bg-white border-b border-gray-200 overflow-hidden"
                    >
                        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                                {/* Distance Filter */}
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-2">
                                        Distance from Mutt
                                    </label>
                                    <select
                                        value={filters.distanceType}
                                        onChange={(e) => handleFilterChange('distanceType', e.target.value)}
                                        className="input-primary"
                                    >
                                        <option value="">All Distances</option>
                                        <option value="walkable">Walking Distance (&lt;500m)</option>
                                        <option value="auto">Auto Distance (&gt;500m)</option>
                                    </select>
                                </div>

                                {/* Price Filter */}
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-2">
                                        Max Price per Night
                                    </label>
                                    <select
                                        value={filters.priceMax}
                                        onChange={(e) => handleFilterChange('priceMax', e.target.value)}
                                        className="input-primary"
                                    >
                                        <option value="">Any Price</option>
                                        <option value="500">Under ₹500</option>
                                        <option value="1000">Under ₹1000</option>
                                        <option value="1500">Under ₹1500</option>
                                        <option value="2000">Under ₹2000</option>
                                    </select>
                                </div>

                                {/* Availability Filter */}
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-2">
                                        Availability
                                    </label>
                                    <select
                                        value={filters.availability}
                                        onChange={(e) => handleFilterChange('availability', e.target.value)}
                                        className="input-primary"
                                    >
                                        <option value="">All</option>
                                        <option value="available">Available Now</option>
                                        <option value="limited">Limited Rooms</option>
                                    </select>
                                </div>

                                {/* Clear Filters */}
                                <div className="flex items-end">
                                    <button
                                        onClick={clearFilters}
                                        className="w-full px-4 py-3 text-gray-600 hover:text-gray-900 border-2 border-gray-200 hover:border-gray-300 rounded-xl transition-colors flex items-center justify-center gap-2"
                                    >
                                        <X size={18} />
                                        Clear All
                                    </button>
                                </div>
                            </div>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Results Section */}
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
                {/* Results Count */}
                <div className="mb-6">
                    <h1 className="text-2xl font-bold text-gray-900">
                        Bhakta Nivas: Private Lodges in Mantralayam
                    </h1>
                    <p className="text-gray-600 mt-1">
                        Near Sri Raghavendra Swamy Mutt
                    </p>
                </div>

                {/* Lodge Grid */}
                {filteredLodges.length > 0 ? (
                    <div className={`grid gap-6 ${viewMode === 'grid'
                        ? 'grid-cols-1 md:grid-cols-2 lg:grid-cols-3'
                        : 'grid-cols-1'
                        }`}>
                        {filteredLodges.map((lodge, index) => (
                            <LodgeCard key={lodge._id || lodge.id} lodge={lodge} index={index} />
                        ))}
                    </div>
                ) : (
                    <div className="text-center py-16">
                        <div className="w-24 h-24 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
                            <MapPin size={40} className="text-gray-400" />
                        </div>
                        <h3 className="text-xl font-semibold text-gray-900 mb-2">
                            No lodges match your filters
                        </h3>
                        <p className="text-gray-600 mb-4">
                            Try adjusting your filters to see more results
                        </p>
                        <button
                            onClick={clearFilters}
                            className="btn-primary"
                        >
                            Clear All Filters
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
};

export default LodgeList;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import {
    MapPin,
    Clock,
    Star,
    Train,
    Bus,
    Navigation,
    Image as ImageIcon,
    ChevronLeft,
    ChevronRight,
    Loader2,
    Info
} from 'lucide-react';
import { templeAPI, getImageUrl } from '../services/api';

const TempleDetails = () => {
    const [temples, setTemples] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeImage, setActiveImage] = useState({});

    useEffect(() => {
        const fetchTemples = async () => {
            try {
                const data = await templeAPI.getAll();
                setTemples(Array.isArray(data) ? data : []);
            } catch (err) {
                console.error('Error fetching temples:', err);
            } finally {
                setLoading(false);
            }
        };
        fetchTemples();
    }, []);

    const nextImage = (templeId, total) => {
        setActiveImage(prev => ({
            ...prev,
            [templeId]: ((prev[templeId] || 0) + 1) % total
        }));
    };

    const prevImage = (templeId, total) => {
        setActiveImage(prev => ({
            ...prev,
            [templeId]: ((prev[templeId] || 0) - 1 + total) % total
        }));
    };

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <Loader2 className="animate-spin text-primary-600" size={40} />
            </div>
        );
    }

    if (temples.length === 0) {
        return (
            <div className="min-h-screen flex flex-col items-center justify-center text-gray-500 px-4">
                <Info size={48} className="mb-4 text-gray-400" />
                <h2 className="text-xl font-semibold mb-2">No Temple Details Available</h2>
                <p className="text-sm">Temple information will be updated soon. Please check back later.</p>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gradient-to-b from-orange-50 to-white">
            {/* Hero Banner */}
            <div className="bg-gradient-to-r from-orange-600 to-amber-500 text-white py-12 px-4">
                <div className="max-w-6xl mx-auto text-center">
                    <motion.h1
                        initial={{ opacity: 0, y: -20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="text-3xl sm:text-4xl font-bold mb-3"
                    >
                        🙏 Temple Details
                    </motion.h1>
                    <p className="text-orange-100 text-sm sm:text-base max-w-xl mx-auto">
                        Complete information about temples, darshan timings, and how to reach
                    </p>
                </div>
            </div>

            <div className="max-w-6xl mx-auto px-4 py-8 space-y-10">
                {temples.map((temple, idx) => (
                    <motion.div
                        key={temple._id || idx}
                        initial={{ opacity: 0, y: 30 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: idx * 0.1 }}
                        className="bg-white rounded-2xl shadow-lg overflow-hidden border border-gray-100"
                    >
                        {/* Image Gallery */}
                        {temple.images && temple.images.length > 0 && (
                            <div className="relative h-64 sm:h-80 bg-gray-100">
                                <img
                                    src={getImageUrl(temple.images[activeImage[temple._id] || 0])}
                                    alt={temple.name}
                                    className="w-full h-full object-cover"
                                    onError={(e) => {
                                        e.target.onerror = null;
                                        e.target.src = 'https://via.placeholder.com/400x300?text=No+Image';
                                    }}
                                />
                                {temple.images.length > 1 && (
                                    <>
                                        <button
                                            onClick={() => prevImage(temple._id, temple.images.length)}
                                            className="absolute left-3 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white p-2 rounded-full shadow-md transition-all"
                                        >
                                            <ChevronLeft size={20} />
                                        </button>
                                        <button
                                            onClick={() => nextImage(temple._id, temple.images.length)}
                                            className="absolute right-3 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white p-2 rounded-full shadow-md transition-all"
                                        >
                                            <ChevronRight size={20} />
                                        </button>
                                        <div className="absolute bottom-3 left-1/2 -translate-x-1/2 flex gap-1.5">
                                            {temple.images.map((_, i) => (
                                                <span
                                                    key={i}
                                                    className={`w-2 h-2 rounded-full transition-all ${(activeImage[temple._id] || 0) === i
                                                        ? 'bg-white w-4'
                                                        : 'bg-white/50'
                                                        }`}
                                                />
                                            ))}
                                        </div>
                                    </>
                                )}
                            </div>
                        )}

                        {/* Content */}
                        <div className="p-5 sm:p-8">
                            <h2 className="text-2xl sm:text-3xl font-bold text-gray-900 mb-2">{temple.name}</h2>

