                                                        disabled={updatingStatus === booking._id}
                                                        className={`p-2 rounded-lg transition-colors ${action.color} disabled:opacity-50`}
                                                        title={action.label}
                                                    >
                                                        {updatingStatus === booking._id ? (
                                                            <Loader2 size={18} className="animate-spin" />
                                                        ) : (
                                                            <action.icon size={18} />
                                                        )}
                                                    </button>
                                                ))}
                                            </div>
                                        </td>
                                    </tr>
