                    </table>
                </div>
            </div>

            {/* Booking Details Modal */}
            {selectedBooking && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
                    <div className="bg-white rounded-xl max-w-2xl w-full max-h-[90vh] overflow-y-auto">
                        <div className="p-6 border-b flex justify-between items-center sticky top-0 bg-white">
                            <h3 className="text-xl font-bold">Booking Details</h3>
                            <button onClick={() => setSelectedBooking(null)} className="p-2 hover:bg-gray-100 rounded-lg">
                                <X size={20} />
                            </button>
                        </div>
                        <div className="p-6 space-y-6">
                            {/* Booking Info */}
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <p className="text-sm text-gray-500">Booking ID</p>
                                    <p className="font-mono font-bold text-indigo-600">{selectedBooking.bookingId}</p>
                                </div>
                                <div>
                                    <p className="text-sm text-gray-500">Status</p>
                                    <span className={`px-3 py-1 rounded-full text-sm font-medium capitalize ${getStatusColor(selectedBooking.status)}`}>
                                        {selectedBooking.status}
                                    </span>
                                </div>
                            </div>

                            {/* Guest Details */}
                            <div className="bg-gray-50 p-4 rounded-lg">
                                <h4 className="font-semibold mb-3">Guest Information</h4>
                                <div className="grid grid-cols-2 gap-4 text-sm">
                                    <div>
                                        <p className="text-gray-500">Name</p>
                                        <p className="font-medium">{selectedBooking.customerDetails?.name}</p>
                                    </div>
                                    <div>
                                        <p className="text-gray-500">Mobile</p>
                                        <p className="font-medium">{selectedBooking.customerDetails?.mobile}</p>
                                    </div>
                                    <div>
                                        <p className="text-gray-500">Email</p>
                                        <p className="font-medium">{selectedBooking.customerDetails?.email || 'N/A'}</p>
                                    </div>
                                    <div>
                                        <p className="text-gray-500">Guests</p>
                                        <p className="font-medium">{selectedBooking.guests || 1}</p>
                                    </div>
                                </div>
                            </div>

                            {/* Stay Details */}
                            <div className="bg-gray-50 p-4 rounded-lg">
                                <h4 className="font-semibold mb-3">Stay Details</h4>
                                <div className="grid grid-cols-2 gap-4 text-sm">
                                    <div>
                                        <p className="text-gray-500">Lodge</p>
                                        <p className="font-medium">{selectedBooking.lodgeName || selectedBooking.lodge?.name}</p>
                                    </div>
                                    <div>
                                        <p className="text-gray-500">Room</p>
                                        <p className="font-medium">{selectedBooking.roomName || selectedBooking.roomType || 'Standard'}</p>
                                    </div>
                                    <div>
                                        <p className="text-gray-500">Check In</p>
                                        <p className="font-medium">
                                            {selectedBooking.checkIn ? format(new Date(selectedBooking.checkIn), 'MMM dd, yyyy') : 'N/A'}
                                        </p>
                                        {selectedBooking.checkInTime && (
                                            <p className="text-xs text-primary-600 flex items-center gap-1 mt-1">
                                                <Clock size={12} />
                                                {formatTo12Hour(selectedBooking.checkInTime)}
                                            </p>
                                        )}
                                    </div>
                                    <div>
                                        <p className="text-gray-500">Check Out</p>
                                        <p className="font-medium">
                                            {selectedBooking.checkOut ? format(new Date(selectedBooking.checkOut), 'MMM dd, yyyy') : 'N/A'}
                                        </p>
                                        {selectedBooking.checkInTime && (
                                            <p className="text-xs text-primary-600 flex items-center gap-1 mt-1">
                                                <Clock size={12} />
                                                {formatTo12Hour(calculateCheckOutTime(selectedBooking.checkIn, selectedBooking.checkInTime).checkOutTime)} (auto)
                                            </p>
                                        )}
                                        {selectedBooking.status === 'checked-in' && (
                                            <div className="mt-2">
                                                <p className="text-xs text-gray-500 mb-1">Time elapsed since check-in:</p>
                                                <LiveTimer checkInDate={selectedBooking.checkIn} checkInTime={selectedBooking.checkInTime} />
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>

                            {/* ID Proof Details */}
                            {(selectedBooking.idType || selectedBooking.idNumber || selectedBooking.customerDetails?.idType) && (
                                <div className="bg-amber-50 p-4 rounded-lg">
                                    <h4 className="font-semibold mb-3 text-amber-800">ID Proof Details</h4>
                                    <div className="grid grid-cols-2 gap-4 text-sm">
                                        <div>
                                            <p className="text-amber-700">ID Type</p>
                                            <p className="font-medium text-amber-900">{selectedBooking.idType || selectedBooking.customerDetails?.idType || 'N/A'}</p>
                                        </div>
                                        <div>
                                            <p className="text-amber-700">ID Number</p>
                                            <p className="font-medium font-mono text-amber-900">{selectedBooking.idNumber || selectedBooking.customerDetails?.idNumber || 'N/A'}</p>
                                        </div>
                                    </div>
                                </div>
                            )}

                            {/* Payment Details */}
                            <div className="bg-green-50 p-4 rounded-lg border border-green-200">
                                <h4 className="font-semibold mb-3 text-green-800">Payment Information</h4>
                                <div className="grid grid-cols-2 gap-4 text-sm mb-4">
                                    <div>
                                        <p className="text-green-700">Payment Method</p>
                                        <span className={`inline-flex items-center gap-1 px-2 py-1 rounded-full text-sm font-medium ${selectedBooking.paymentMethod === 'upi' || selectedBooking.paymentMethod === 'online'
                                            ? 'bg-blue-100 text-blue-700'
                                            : 'bg-orange-100 text-orange-700'
                                            }`}>
                                            {selectedBooking.paymentMethod === 'upi' || selectedBooking.paymentMethod === 'online' ? (
                                                <><CreditCard size={14} /> Online Payment</>
                                            ) : (
                                                <><Banknote size={14} /> Pay at Lodge (Cash)</>
                                            )}
                                        </span>
                                    </div>
                                    <div>
                                        <p className="text-green-700">Payment Status</p>
                                        {(() => {
                                            const hasBal = selectedBooking.balanceAmount > 0;
                                            const isPaid = selectedBooking.paymentStatus === 'paid';
                                            if (isPaid && !hasBal) {
                                                return <span className="inline-flex px-2 py-1 rounded-full text-xs font-medium bg-green-200 text-green-800">✅ Fully Paid</span>;
                                            } else if (isPaid && hasBal) {
                                                return <span className="inline-flex px-2 py-1 rounded-full text-xs font-medium bg-blue-200 text-blue-800">💳 Partially Paid</span>;
                                            } else {
                                                return <span className="inline-flex px-2 py-1 rounded-full text-xs font-medium bg-yellow-200 text-yellow-800">⏳ Pending</span>;
                                            }
                                        })()}
                                    </div>
                                    {selectedBooking.paymentId && (
                                        <div className="col-span-2">
                                            <p className="text-green-700">Payment ID</p>
                                            <p className="font-mono text-xs text-green-900 bg-green-100 p-2 rounded mt-1">
                                                {selectedBooking.paymentId}
                                            </p>
                                        </div>
                                    )}
                                </div>

                                {/* Amount Breakdown */}
                                <div className="space-y-2 pt-3 border-t border-green-200">
                                    {selectedBooking.amountPaid > 0 && (
                                        <div className="flex justify-between items-center text-sm">
                                            <span className="text-green-700">Paid Online</span>
                                            <span className="font-semibold text-green-700">₹{selectedBooking.amountPaid?.toLocaleString()} ✅</span>
                                        </div>
                                    )}
                                    {selectedBooking.balanceAmount > 0 && (
                                        <div className="flex justify-between items-center text-sm">
                                            <span className="text-red-600">Balance Due</span>
                                            <span className="font-semibold text-red-600">₹{selectedBooking.balanceAmount?.toLocaleString()} 💰</span>
                                        </div>
                                    )}
                                    <div className="flex justify-between items-center pt-2">
                                        <span className="font-semibold text-green-800">Total Amount</span>
                                        <span className="text-2xl font-bold text-green-700">
                                            ₹{selectedBooking.totalAmount?.toLocaleString() || 0}
                                        </span>
                                    </div>
                                </div>

                                {/* Balance Warning */}
                                {selectedBooking.balanceAmount > 0 && (
                                    <div className="mt-3 bg-amber-50 border border-amber-200 rounded-lg p-3">
                                        <p className="text-xs text-amber-800 font-medium">
                                            💰 Balance of <strong>₹{selectedBooking.balanceAmount?.toLocaleString()}</strong> to be collected at lodge during check-in.
                                        </p>
                                    </div>
                                )}

                                {/* Payment Action Button */}
                                {selectedBooking.paymentStatus !== 'paid' && (
                                    <button
                                        onClick={() => handlePaymentUpdate(selectedBooking, 'paid')}
                                        disabled={updatingPayment === selectedBooking._id}
                                        className="w-full mt-4 flex items-center justify-center gap-2 px-4 py-3 bg-green-600 text-white rounded-lg font-medium hover:bg-green-700 transition-colors disabled:opacity-50"
                                    >
                                        {updatingPayment === selectedBooking._id ? (
                                            <Loader2 size={18} className="animate-spin" />
                                        ) : (
                                            <Banknote size={18} />
                                        )}
                                        Mark as Paid (Cash Received)
                                    </button>
                                )}
                            </div>

                            {/* Booking Timestamps */}
                            <div className="flex gap-4 text-xs text-gray-400">
                                <span>Created: {selectedBooking.createdAt ? format(new Date(selectedBooking.createdAt), 'MMM dd, yyyy hh:mm a') : 'N/A'}</span>
                                {selectedBooking.updatedAt && selectedBooking.updatedAt !== selectedBooking.createdAt && (
                                    <span>Updated: {format(new Date(selectedBooking.updatedAt), 'MMM dd, yyyy hh:mm a')}</span>
                                )}
                            </div>

                            {/* Special Requests */}
                            {selectedBooking.specialRequests && (
                                <div>
                                    <h4 className="font-semibold mb-2">Special Requests</h4>
                                    <p className="text-gray-600 text-sm bg-gray-50 p-3 rounded-lg">
                                        {selectedBooking.specialRequests}
                                    </p>
                                </div>
                            )}

                            {/* Actions */}
                            <div className="flex gap-3 pt-4 border-t">
                                {getNextActions(selectedBooking.status).map((action) => (
                                    <button
                                        key={action.status}
                                        onClick={() => handleStatusUpdate(selectedBooking._id, action.status)}
                                        disabled={updatingStatus === selectedBooking._id}
                                        className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors ${action.status === 'cancelled'
                                            ? 'bg-red-100 text-red-700 hover:bg-red-200'
                                            : 'bg-indigo-600 text-white hover:bg-indigo-700'
                                            } disabled:opacity-50`}
                                    >
                                        {updatingStatus === selectedBooking._id ? (
                                            <Loader2 size={18} className="animate-spin" />
                                        ) : (
                                            <action.icon size={18} />
                                        )}
                                        {action.label}
                                    </button>
                                ))}
                                <button
                                    onClick={() => setSelectedBooking(null)}
                                    className="px-4 py-2 border rounded-lg hover:bg-gray-50 ml-auto"
                                >
                                    Close
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default BookingsList;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { dashboardAPI } from '../../services/api';
import { Building2, Users, IndianRupee, CalendarCheck, User, Loader2 } from 'lucide-react';
import { format } from 'date-fns';

const Dashboard = () => {
    const { user } = useAuth();
    const [stats, setStats] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchStats = async () => {
            try {
                setLoading(true);
                // Pass lodgeId if user is not super_admin
                const lodgeId = user?.role === 'super_admin' ? null : user?.lodgeId;
                const data = await dashboardAPI.getStats(lodgeId);
                setStats(data);
            } catch (error) {
                console.error('Error fetching stats:', error);
            } finally {
                setLoading(false);
            }
        };
        fetchStats();
    }, [user]);

    const StatCard = ({ title, value, icon: Icon, color }) => (
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
            <div className="flex justify-between items-start">
                <div>
                    <p className="text-sm font-medium text-gray-500">{title}</p>
                    <h3 className="text-2xl font-bold text-gray-900 mt-2">{value}</h3>
                </div>
                <div className={`p-3 rounded-lg ${color}`}>
                    <Icon size={24} className="text-white" />
                </div>
            </div>
        </div>
    );

    if (loading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="w-8 h-8 animate-spin text-indigo-500" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-bold text-gray-900">Dashboard</h2>
                <p className="text-gray-500">Overview of {user?.role === 'super_admin' ? 'all operations' : 'your lodge performance'}.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard
                    title="Total Revenue"
                    value={`₹${(stats?.totalRevenue || 0).toLocaleString()}`}
                    icon={IndianRupee}
                    color="bg-green-500"
                />
                <StatCard
                    title="Total Bookings"
                    value={stats?.totalBookings || 0}
                    icon={CalendarCheck}
                    color="bg-blue-500"
                />
                <StatCard
                    title="Occupancy Rate"
                    value={`${stats?.occupancyRate || 0}%`}
                    icon={Users}
                    color="bg-purple-500"
                />
                <StatCard
                    title={user?.role === 'super_admin' ? "Active Lodges" : "Total Rooms"}
                    value={user?.role === 'super_admin' ? stats?.totalLodges : stats?.totalRooms}
                    icon={Building2}
                    color="bg-orange-500"
                />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                    <h3 className="font-bold text-gray-900 mb-4">Recent Bookings</h3>
                    <div className="space-y-4">
                        {stats?.recentBookings?.length > 0 ? (
                            stats.recentBookings.map((booking) => (
                                <div key={booking._id} className="flex items-center justify-between py-2 border-b last:border-0 border-gray-50">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center text-gray-500">
                                            <User size={18} />
                                        </div>
                                        <div>
                                            <p className="font-medium text-sm">{booking.customerDetails?.name}</p>
                                            <p className="text-xs text-gray-400">
                                                {booking.createdAt ? format(new Date(booking.createdAt), 'MMM dd, yyyy') : 'N/A'}
                                            </p>
                                        </div>
                                    </div>
                                    <span className={`text-xs font-medium px-2 py-1 rounded ${booking.status === 'confirmed' ? 'bg-green-50 text-green-600' :
                                        booking.status === 'pending' ? 'bg-yellow-50 text-yellow-600' :
                                            'bg-blue-50 text-blue-600'
                                        }`}>
                                        {booking.status}
                                    </span>
                                </div>
                            ))
                        ) : (
                            <p className="text-gray-500 text-center py-4">No recent bookings</p>
                        )}
                    </div>
                </div>

                <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                    <h3 className="font-bold text-gray-900 mb-4">Quick Stats</h3>
                    <div className="space-y-4">
                        <div className="flex justify-between items-center p-3 bg-green-50 rounded-lg">
                            <span className="text-green-700">Today's Revenue</span>
                            <span className="font-bold text-green-700">₹{(stats?.todayRevenue || 0).toLocaleString()}</span>
                        </div>
                        <div className="flex justify-between items-center p-3 bg-yellow-50 rounded-lg">
                            <span className="text-yellow-700">Pending Bookings</span>
                            <span className="font-bold text-yellow-700">{stats?.pendingBookings || 0}</span>
                        </div>
                        <div className="flex justify-between items-center p-3 bg-blue-50 rounded-lg">
                            <span className="text-blue-700">Today's Check-ins</span>
                            <span className="font-bold text-blue-700">{stats?.todayCheckIns || 0}</span>
                        </div>
                        <div className="flex justify-between items-center p-3 bg-gray-50 rounded-lg">
                            <span className="text-gray-600">Avg. Booking Value</span>
                            <span className="font-bold text-gray-900">
                                ₹{stats?.totalBookings > 0 ? Math.round(stats.totalRevenue / stats.totalBookings).toLocaleString() : 0}
                            </span>
                        </div>
                        {user?.role === 'super_admin' && (
                            <>
                                <div className="flex justify-between items-center p-3 bg-purple-50 rounded-lg">
                                    <span className="text-purple-700">Total Lodges</span>
                                    <span className="font-bold text-purple-700">{stats?.totalLodges || 0}</span>
                                </div>
                                <div className="flex justify-between items-center p-3 bg-indigo-50 rounded-lg">
                                    <span className="text-indigo-700">Total Rooms</span>
                                    <span className="font-bold text-indigo-700">{stats?.totalRooms || 0}</span>
                                </div>
                            </>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Dashboard;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { Lock, Mail, AlertCircle, Loader2 } from 'lucide-react';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const { login } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        if (!email || !password) {
            setError('Please fill in all fields');
            return;
        }

        setLoading(true);
        try {
            const result = await login(email, password);
            if (result.success) {
                navigate('/admin/dashboard');
            } else {
                setError(result.message || 'Invalid credentials');
            }
        } catch (err) {
            setError('Server error. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
            <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden">
                <div className="bg-indigo-900 p-8 text-center">
                    <h2 className="text-3xl font-bold text-white mb-2">Welcome Back</h2>
                    <p className="text-indigo-200">Sign in to access your dashboard</p>
                </div>

                <div className="p-8">
                    {error && (
                        <div className="mb-6 p-4 bg-red-50 border-l-4 border-red-500 flex items-center gap-3 text-red-700">
                            <AlertCircle size={20} />
                            <p>{error}</p>
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">Email Address</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                                    <Mail size={18} />
                                </div>
                                <input
                                    type="email"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    className="block w-full pl-10 pr-3 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-colors"
                                    placeholder="admin@example.com"
                                    disabled={loading}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">Password</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                                    <Lock size={18} />
                                </div>
                                <input
                                    type="password"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    className="block w-full pl-10 pr-3 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-colors"
                                    placeholder="••••••••"
                                    disabled={loading}
                                />
                            </div>
                        </div>

                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full bg-indigo-600 text-white py-3 rounded-lg font-semibold hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-200 disabled:opacity-50 flex items-center justify-center gap-2"
                        >
                            {loading ? (
                                <>
                                    <Loader2 size={20} className="animate-spin" />
                                    Signing In...
                                </>
                            ) : (
                                'Sign In'
                            )}
                        </button>
                    </form>

                    <div className="mt-8 pt-6 border-t text-center text-sm text-gray-500">
                        <p className="mb-2">Demo Credentials:</p>
                        <div className="grid grid-cols-2 gap-4 text-xs bg-gray-50 p-3 rounded-lg">
                            <div>
                                <p className="font-semibold text-gray-900">Super Admin</p>
                                <p>super@admin.com</p>
                            </div>
                            <div>
                                <p className="font-semibold text-gray-900">Lodge Admin</p>
                                <p>bhakti@admin.com</p>
                            </div>
                            <div className="col-span-2 text-center text-gray-400 font-mono">
                                password: password
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Login;

import React, { useState, useEffect } from 'react';
import {
    Plus,
    Pencil,
    Trash2,
    X,
    Save,
    Loader2,
    MapPin,
    Clock,
    Star,
    Train,
    Bus,
    Image as ImageIcon,
    Upload,
    AlertCircle
} from 'lucide-react';
import { templeAPI, uploadAPI, BASE_URL, getImageUrl } from '../../services/api';

const emptyTemple = {
    name: '',
    location: '',
    googleMapsLink: '',
    darshanTimings: '',
    specialDarshanTimings: '',
    nearbyRailwayStation: '',
    busTimings: '',
    description: '',
    additionalInfo: '',
    images: []
};

const ManageTemples = () => {
    const [temples, setTemples] = useState([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [showForm, setShowForm] = useState(false);
    const [editingId, setEditingId] = useState(null);
    const [formData, setFormData] = useState({ ...emptyTemple });
    const [error, setError] = useState('');
    const [uploading, setUploading] = useState(false);

    useEffect(() => {
        fetchTemples();
    }, []);

    const fetchTemples = async () => {
        try {
            const data = await templeAPI.getAll();
            setTemples(Array.isArray(data) ? data : []);
        } catch (err) {
            console.error('Error fetching temples:', err);
        } finally {
            setLoading(false);
        }
    };

    const handleChange = (e) => {
        setFormData(prev => ({
            ...prev,
            [e.target.name]: e.target.value
        }));
    };

    const handleImageUpload = async (e) => {
        const file = e.target.files[0];
        if (!file) return;

        setUploading(true);
        try {
            const result = await uploadAPI.uploadImage(file);
            if (result && result.imageUrl) {
                const imageUrl = result.imageUrl.startsWith('http') ? result.imageUrl : `${BASE_URL}${result.imageUrl}`;
                setFormData(prev => ({
                    ...prev,
                    images: [...prev.images, imageUrl]
                }));
            } else {
                throw new Error('Invalid response from server');
            }
        } catch (err) {
            setError('Failed to upload image: ' + err.message);
        } finally {
            setUploading(false);
        }
    };

    const removeImage = (index) => {
        setFormData(prev => ({
            ...prev,
            images: prev.images.filter((_, i) => i !== index)
        }));
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!formData.name.trim()) {
            setError('Temple name is required.');
            return;
        }

        setSaving(true);
        setError('');
        try {
            if (editingId) {
                await templeAPI.update(editingId, formData);
            } else {
                await templeAPI.create(formData);
            }
            setShowForm(false);
            setEditingId(null);
            setFormData({ ...emptyTemple });
            await fetchTemples();
        } catch (err) {
            setError('Failed to save temple: ' + err.message);
        } finally {
            setSaving(false);
        }
    };

    const handleEdit = (temple) => {
        setFormData({
            name: temple.name || '',
            location: temple.location || '',
            googleMapsLink: temple.googleMapsLink || '',
            darshanTimings: temple.darshanTimings || '',
            specialDarshanTimings: temple.specialDarshanTimings || '',
            nearbyRailwayStation: temple.nearbyRailwayStation || '',
            busTimings: temple.busTimings || '',
            description: temple.description || '',
            additionalInfo: temple.additionalInfo || '',
            images: temple.images || []
        });
        setEditingId(temple._id);
        setShowForm(true);
        setError('');
    };

    const handleDelete = async (id) => {
        if (!window.confirm('Are you sure you want to delete this temple?')) return;
        try {
            await templeAPI.delete(id);
            await fetchTemples();
        } catch (err) {
            setError('Failed to delete temple: ' + err.message);
        }
    };

    const openAddForm = () => {
        setFormData({ ...emptyTemple });
        setEditingId(null);
        setShowForm(true);
        setError('');
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="animate-spin text-indigo-600" size={32} />
            </div>
        );
    }

    return (
        <div>
            <div className="flex items-center justify-between mb-6">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Temple Details</h1>
                    <p className="text-sm text-gray-500">Manage temple information displayed on the website</p>
                </div>
                {!showForm && (
                    <button
                        onClick={openAddForm}
                        className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors text-sm font-medium"
                    >
                        <Plus size={18} />
                        Add Temple
                    </button>
                )}
            </div>

            {error && (
                <div className="mb-4 p-3 bg-red-50 border border-red-200 rounded-lg flex items-center gap-2 text-red-700 text-sm">
                    <AlertCircle size={16} />
                    {error}
                </div>
            )}

            {/* Form */}
            {showForm && (
                <div className="bg-white rounded-xl shadow-sm border p-6 mb-6">
                    <div className="flex items-center justify-between mb-4">
                        <h2 className="text-lg font-semibold">{editingId ? 'Edit Temple' : 'Add New Temple'}</h2>
                        <button
                            onClick={() => { setShowForm(false); setEditingId(null); setError(''); }}
                            className="p-1.5 text-gray-400 hover:text-gray-600 transition-colors"
                        >
                            <X size={20} />
                        </button>
                    </div>
                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Temple Name *</label>
                                <input
                                    type="text"
                                    name="name"
                                    value={formData.name}
                                    onChange={handleChange}
                                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                                    placeholder="e.g. Sri Raghavendra Swamy Mutt"
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Location</label>
                                <input
                                    type="text"
                                    name="location"
                                    value={formData.location}
                                    onChange={handleChange}
                                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                                    placeholder="e.g. Mantralayam, Andhra Pradesh"
                                />
                            </div>
                            <div className="md:col-span-2">
                                <label className="block text-sm font-medium text-gray-700 mb-1">Google Maps Link</label>
                                <input
                                    type="url"
                                    name="googleMapsLink"
                                    value={formData.googleMapsLink}
                                    onChange={handleChange}
                                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                                    placeholder="https://maps.google.com/..."
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Darshan Timings</label>
                                <textarea
                                    name="darshanTimings"
                                    value={formData.darshanTimings}
                                    onChange={handleChange}
                                    rows={3}
                                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                                    placeholder="e.g. Morning: 6:00 AM - 1:00 PM&#10;Evening: 4:00 PM - 8:00 PM"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Special / VIP Darshan Timings</label>
                                <textarea
                                    name="specialDarshanTimings"
                                    value={formData.specialDarshanTimings}
                                    onChange={handleChange}
                                    rows={3}
                                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                                    placeholder="e.g. VIP Darshan: 7:00 AM - 9:00 AM"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Nearby Railway Station</label>
                                <textarea
                                    name="nearbyRailwayStation"
                                    value={formData.nearbyRailwayStation}
                                    onChange={handleChange}
                                    rows={3}
                                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                                    placeholder="e.g. Mantralayam Road (MAYE) - 15 km"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Bus Timings</label>
                                <textarea
                                    name="busTimings"
                                    value={formData.busTimings}
                                    onChange={handleChange}
                                    rows={3}
                                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                                    placeholder="e.g. APSRTC buses from Kurnool, Hyderabad"
                                />
                            </div>
                            <div className="md:col-span-2">
                                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                                <textarea
                                    name="description"
                                    value={formData.description}
                                    onChange={handleChange}
                                    rows={4}
                                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                                    placeholder="Detailed description about the temple..."
                                />
                            </div>
                            <div className="md:col-span-2">
                                <label className="block text-sm font-medium text-gray-700 mb-1">Additional Information</label>
                                <textarea
                                    name="additionalInfo"
                                    value={formData.additionalInfo}
                                    onChange={handleChange}
                                    rows={4}
                                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                                    placeholder="Any extra details, package costs, special notes..."
                                />
                            </div>
                        </div>

                        {/* Image Upload */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">Images</label>
                            <div className="flex flex-wrap gap-3 mb-3">
                                {formData.images.map((img, i) => (
                                    <div key={i} className="relative w-24 h-24 rounded-lg overflow-hidden border group">
                                        <img src={img} alt={`Temple ${i + 1}`} className="w-full h-full object-cover" />
                                        <button
                                            type="button"
                                            onClick={() => removeImage(i)}
                                            className="absolute top-1 right-1 bg-red-500 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
                                        >
                                            <X size={14} />
                                        </button>
                                    </div>
                                ))}
                                <label className="w-24 h-24 rounded-lg border-2 border-dashed border-gray-300 flex flex-col items-center justify-center cursor-pointer hover:border-indigo-400 transition-colors">
                                    {uploading ? (
                                        <Loader2 size={20} className="animate-spin text-gray-400" />
                                    ) : (
                                        <>
                                            <Upload size={20} className="text-gray-400 mb-1" />
                                            <span className="text-xs text-gray-400">Upload</span>
                                        </>
                                    )}
                                    <input
                                        type="file"
                                        accept="image/*"
                                        className="hidden"
                                        onChange={handleImageUpload}
                                        disabled={uploading}
                                    />
                                </label>
                            </div>
                        </div>

                        <div className="flex gap-3 pt-2">
                            <button
                                type="submit"
                                disabled={saving}
                                className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors text-sm font-medium disabled:opacity-50"
                            >
                                {saving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
                                {editingId ? 'Update Temple' : 'Save Temple'}
                            </button>
                            <button
                                type="button"
                                onClick={() => { setShowForm(false); setEditingId(null); setError(''); }}
                                className="px-5 py-2.5 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors text-sm font-medium"
                            >
                                Cancel
                            </button>
                        </div>
                    </form>
                </div>
            )}

            {/* Temple List */}
            {temples.length === 0 && !showForm ? (
                <div className="text-center py-16 text-gray-500">
                    <MapPin size={48} className="mx-auto mb-3 text-gray-300" />
