            ) : (
                <div className="space-y-4">
                    {temples.map((temple) => (
                        <div key={temple._id} className="bg-white rounded-xl shadow-sm border p-5 flex flex-col sm:flex-row gap-4">
                            {/* Thumbnail */}
                            {temple.images && temple.images.length > 0 ? (
                                <img
                                    src={getImageUrl(temple.images[0])}
