                                    className="w-full sm:w-32 h-32 rounded-lg object-cover flex-shrink-0"
                                    onError={(e) => {
                                        e.target.onerror = null;
                                        e.target.src = 'https://via.placeholder.com/400x300?text=No+Image';
                                    }}
                                />
                            ) : (
                                <div className="w-full sm:w-32 h-32 rounded-lg bg-gray-100 flex items-center justify-center flex-shrink-0">
                                    <ImageIcon size={24} className="text-gray-300" />
                                </div>
                            )}

                            {/* Info */}
                            <div className="flex-1 min-w-0">
                                <h3 className="font-semibold text-lg text-gray-900">{temple.name}</h3>
                                {temple.location && (
                                    <p className="text-sm text-gray-500 flex items-center gap-1 mt-1">
                                        <MapPin size={14} /> {temple.location}
                                    </p>
                                )}
                                {temple.description && (
                                    <p className="text-sm text-gray-600 mt-2 line-clamp-2">{temple.description}</p>
                                )}
                                <div className="flex flex-wrap gap-2 mt-3">
                                    {temple.darshanTimings && (
                                        <span className="text-xs bg-orange-50 text-orange-700 px-2 py-1 rounded-full flex items-center gap-1">
                                            <Clock size={12} /> Darshan
                                        </span>
                                    )}
                                    {temple.specialDarshanTimings && (
                                        <span className="text-xs bg-amber-50 text-amber-700 px-2 py-1 rounded-full flex items-center gap-1">
                                            <Star size={12} /> Special Darshan
                                        </span>
                                    )}
                                    {temple.nearbyRailwayStation && (
                                        <span className="text-xs bg-blue-50 text-blue-700 px-2 py-1 rounded-full flex items-center gap-1">
                                            <Train size={12} /> Railway
                                        </span>
                                    )}
                                    {temple.busTimings && (
                                        <span className="text-xs bg-green-50 text-green-700 px-2 py-1 rounded-full flex items-center gap-1">
                                            <Bus size={12} /> Bus
