                                    )}
                                </div>
                            </div>

                            {/* Actions */}
                            <div className="flex sm:flex-col gap-2 flex-shrink-0">
                                <button
                                    onClick={() => handleEdit(temple)}
                                    className="flex items-center gap-1.5 px-3 py-2 text-sm text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
