    // overrides: { 'YYYY-MM-DD': { 'Non-AC': { _id, price }, ... } }
    const [overrides, setOverrides] = useState({});

    // blockedDates: { 'YYYY-MM-DD': { _id, reason } }
    const [blockedDates, setBlockedDates] = useState({});

    // Selected day panel
    const [selectedDay, setSelectedDay] = useState(null);
    const [editPrices, setEditPrices] = useState({});
    const [editBlocked, setEditBlocked] = useState(false);
    const [saving, setSaving] = useState(false);
    const [loadingPrices, setLoadingPrices] = useState(false);

    // Load lodges on mount
    useEffect(() => {
        lodgeAPI.getAll().then(data => {
            if (Array.isArray(data) && data.length > 0) {
                setLodges(data);
                setSelectedLodge(data[0]);
            }
        });
    }, []);

    // Load base prices from rooms when lodge changes
    useEffect(() => {
        if (!selectedLodge) return;
        const rooms = selectedLodge.rooms || [];
        const bp = {};
        for (const rt of ROOM_TYPES) {
            const room = rooms.find(r => r.type === rt);
            if (room) bp[rt] = room.price;
        }
        setBasePrices(bp);
        setSelectedDay(null);
        setOverrides({});
    }, [selectedLodge]);

    // Load overrides when lodge or month changes
    useEffect(() => {
        if (!selectedLodge) return;
        const monthStr = toMonthStr(year, month);
        setLoadingPrices(true);

        Promise.all([
            dailyPriceAPI.getByMonth(selectedLodge._id, monthStr),
            blockedDatesAPI.getByMonth(selectedLodge._id, monthStr)
        ]).then(([pricesData, blocksData]) => {
            const map = {};
            if (Array.isArray(pricesData)) {
                pricesData.forEach(item => {
                    if (!map[item.date]) map[item.date] = {};
                    map[item.date][item.roomType] = { _id: item._id, price: item.price };
                });
            }
            setOverrides(map);

            const blockMap = {};
            if (Array.isArray(blocksData)) {
                blocksData.forEach(b => {
                    blockMap[b.date] = { _id: b._id, reason: b.reason };
                });
            }
            setBlockedDates(blockMap);
        })
            .catch(() => {
                setOverrides({});
                setBlockedDates({});
            })
            .finally(() => setLoadingPrices(false));
    }, [selectedLodge, year, month]);

    const prevMonth = () => {
        if (month === 0) { setYear(y => y - 1); setMonth(11); }
        else setMonth(m => m - 1);
        setSelectedDay(null);
    };

    const nextMonth = () => {
        if (month === 11) { setYear(y => y + 1); setMonth(0); }
        else setMonth(m => m + 1);
        setSelectedDay(null);
    };

    const handleDayClick = (day) => {
        if (!day) return;
        const dateStr = toYMD(year, month, day);
        setSelectedDay(dateStr);
        // Pre-fill with existing overrides or base prices
        const dayOverrides = overrides[dateStr] || {};
        const prices = {};
        for (const rt of ROOM_TYPES) {
            prices[rt] = dayOverrides[rt] ? String(dayOverrides[rt].price) : (basePrices[rt] != null ? String(basePrices[rt]) : '');
        }
        setEditPrices(prices);
        setEditBlocked(!!blockedDates[dateStr]);
    };

    const handleSave = async () => {
        if (!selectedLodge || !selectedDay) return;
        setSaving(true);
        try {
            const newOverrides = { ...overrides };
            if (!newOverrides[selectedDay]) newOverrides[selectedDay] = {};

            for (const rt of ROOM_TYPES) {
                const val = editPrices[rt];
                const baseVal = basePrices[rt];
                const numVal = parseFloat(val);
                if (val === '' || isNaN(numVal)) continue;

                // Only save if different from base price or already overridden
                const doc = await dailyPriceAPI.upsert({
                    lodgeId: selectedLodge._id,
                    date: selectedDay,
                    roomType: rt,
                    price: numVal
                });
                newOverrides[selectedDay][rt] = { _id: doc._id, price: doc.price };
            }
            setOverrides(newOverrides);

            // Handle block toggles
            const wasBlocked = !!blockedDates[selectedDay];
            if (editBlocked && !wasBlocked) {
                const doc = await blockedDatesAPI.block({ lodgeId: selectedLodge._id, date: selectedDay });
                setBlockedDates(prev => ({ ...prev, [selectedDay]: { _id: doc._id, reason: doc.reason } }));
            } else if (!editBlocked && wasBlocked) {
                const existingBlockId = blockedDates[selectedDay]._id;
                await blockedDatesAPI.unblock(existingBlockId);
                setBlockedDates(prev => {
                    const newBlocks = { ...prev };
                    delete newBlocks[selectedDay];
                    return newBlocks;
                });
            }

        } catch (err) {
            alert('Failed to save prices: ' + err.message);
        } finally {
            setSaving(false);
        }
    };

    const handleReset = async (rt) => {
        if (!selectedLodge || !selectedDay) return;
        const existing = overrides[selectedDay]?.[rt];
        if (!existing) return; // nothing to reset
        try {
            await dailyPriceAPI.remove(existing._id);
            const newOverrides = { ...overrides };
            delete newOverrides[selectedDay][rt];
            if (Object.keys(newOverrides[selectedDay]).length === 0) {
                delete newOverrides[selectedDay];
            }
            setOverrides(newOverrides);
            // Reset edit price to base
            setEditPrices(prev => ({ ...prev, [rt]: basePrices[rt] != null ? String(basePrices[rt]) : '' }));
        } catch (err) {
            alert('Failed to reset price: ' + err.message);
        }
    };

    const cells = getMonthMatrix(year, month);
    const monthName = new Date(year, month).toLocaleString('default', { month: 'long', year: 'numeric' });

    const getDayPrices = (day) => {
        if (!day) return null;
        const dateStr = toYMD(year, month, day);
        return overrides[dateStr] || null;
    };

    const isToday = (day) => {
        const t = new Date();
        return day === t.getDate() && month === t.getMonth() && year === t.getFullYear();
    };

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h2 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                        <CalendarDays size={24} className="text-indigo-600" />
                        Price Calendar
                    </h2>
                    <p className="text-gray-500 text-sm mt-1">Set daily room prices for any date. Dates without override use the default room price.</p>
                </div>

                {/* Lodge selector */}
                <select
                    className="px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 text-sm bg-white shadow-sm"
                    value={selectedLodge?._id || ''}
                    onChange={e => {
                        const lodge = lodges.find(l => l._id === e.target.value);
                        setSelectedLodge(lodge || null);
                    }}
                >
                    {lodges.map(l => (
                        <option key={l._id} value={l._id}>{l.name}</option>
                    ))}
                </select>
            </div>

            {/* Legend */}
            <div className="flex flex-wrap gap-2 text-xs">
                {ROOM_TYPES.map(rt => (
                    <span key={rt} className={`px-2 py-1 rounded-full font-medium ${ROOM_COLORS[rt]}`}>
                        {rt}
                    </span>
                ))}
                <span className="text-gray-400 ml-2 self-center">— shown on overridden dates</span>
            </div>

            <div className="flex flex-col lg:flex-row gap-6">
                {/* Calendar */}
                <div className="bg-white rounded-2xl shadow-sm border flex-1 overflow-hidden">
                    {/* Month nav */}
                    <div className="flex items-center justify-between px-6 py-4 border-b bg-gray-50">
                        <button onClick={prevMonth} className="p-2 hover:bg-gray-200 rounded-lg transition-colors">
                            <ChevronLeft size={18} />
                        </button>
                        <div className="flex items-center gap-3">
                            <h3 className="font-semibold text-gray-800">{monthName}</h3>
                            {loadingPrices && <Loader2 size={16} className="animate-spin text-indigo-500" />}
                        </div>
                        <button onClick={nextMonth} className="p-2 hover:bg-gray-200 rounded-lg transition-colors">
                            <ChevronRight size={18} />
                        </button>
                    </div>

                    {/* Day headers */}
                    <div className="grid grid-cols-7 border-b">
                        {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => (
                            <div key={d} className="text-center py-2 text-xs font-semibold text-gray-400 uppercase">
                                {d}
                            </div>
                        ))}
                    </div>

                    {/* Cells */}
                    <div className="grid grid-cols-7">
                        {cells.map((day, idx) => {
                            const dateStr = day ? toYMD(year, month, day) : null;
                            const dayPrices = getDayPrices(day);
                            const isSelected = dateStr === selectedDay;
                            const isLodgeBlocked = dateStr && blockedDates[dateStr];
                            const todayFlag = day && isToday(day);

                            return (
                                <div
                                    key={idx}
                                    onClick={() => handleDayClick(day)}
                                    className={`min-h-[72px] p-1.5 border-b border-r cursor-pointer transition-colors relative
                                        ${!day ? 'bg-gray-50 cursor-default' : 'hover:bg-indigo-50'}
                                        ${isSelected ? 'bg-indigo-100 ring-2 ring-indigo-400 ring-inset' : ''}
                                        ${isLodgeBlocked ? 'bg-red-50' : ''}
                                    `}
                                >
                                    {day && (
                                        <>
                                            <span className={`text-xs font-semibold w-6 h-6 flex items-center justify-center rounded-full mb-1
                                                ${todayFlag ? (isLodgeBlocked ? 'bg-red-600 text-white' : 'bg-indigo-600 text-white') : (isLodgeBlocked ? 'text-red-700' : 'text-gray-700')}`}>
                                                {day}
                                            </span>
                                            {isLodgeBlocked ? (
                                                <div className="flex flex-col gap-0.5 items-center justify-center mt-2 text-red-500">
                                                    <ShieldBan size={16} />
                                                    <span className="text-[10px] font-bold uppercase tracking-wider">Blocked</span>
                                                </div>
                                            ) : (
                                                <div className="flex flex-col gap-0.5">
                                                    {dayPrices && Object.entries(dayPrices).map(([rt, info]) => (
                                                        <span key={rt} className={`text-[10px] px-1 py-0.5 rounded font-medium truncate ${ROOM_COLORS[rt]}`}>
                                                            {rt.slice(0, 1)}: ₹{info.price}
                                                        </span>
                                                    ))}
                                                </div>
                                            )}
                                        </>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* Edit Panel */}
                {selectedDay ? (
                    <div className="bg-white rounded-2xl shadow-sm border w-full lg:w-72 p-5 self-start">
                        <div className="flex items-center justify-between mb-4">
                            <h4 className="font-semibold text-gray-800">
                                {new Date(selectedDay + 'T00:00:00').toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })}
                            </h4>
                            <button onClick={() => setSelectedDay(null)} className="p-1 text-gray-400 hover:text-gray-600">
                                <X size={18} />
                            </button>
                        </div>

                        <div className="mb-4">
                            <label className="flex items-center gap-2 cursor-pointer p-3 bg-red-50 border border-red-100 rounded-lg select-none">
                                <input
                                    type="checkbox"
                                    checked={editBlocked}
                                    onChange={(e) => setEditBlocked(e.target.checked)}
                                    className="w-4 h-4 text-red-600 rounded focus:ring-red-500 cursor-pointer"
                                />
                                <span className="text-sm font-semibold text-red-700 flex items-center gap-1">
                                    <ShieldBan size={14} /> Block Lodge on this Day
                                </span>
                            </label>
                            {editBlocked && <p className="text-xs text-red-600 mt-1 ml-1">Lodge will not be bookable on this date.</p>}
                        </div>

                        {!editBlocked && (
                            <div className="space-y-3">
                                {ROOM_TYPES.map(rt => {
                                    const isOverridden = !!overrides[selectedDay]?.[rt];
                                    return (
                                        <div key={rt}>
                                            <div className="flex items-center justify-between mb-1">
                                                <label className={`text-xs font-semibold px-2 py-0.5 rounded-full ${ROOM_COLORS[rt]}`}>
                                                    {rt}
                                                </label>
                                                {isOverridden && (
                                                    <button
                                                        onClick={() => handleReset(rt)}
                                                        title="Reset to default price"
                                                        className="flex items-center gap-1 text-xs text-red-500 hover:text-red-700"
                                                    >
                                                        <RotateCcw size={11} /> Reset
                                                    </button>
                                                )}
                                            </div>
                                            <div className="relative">
                                                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                                                    <IndianRupee size={14} />
                                                </span>
                                                <input
                                                    type="number"
                                                    min="0"
                                                    value={editPrices[rt] || ''}
                                                    onChange={e => setEditPrices(prev => ({ ...prev, [rt]: e.target.value }))}
                                                    placeholder={basePrices[rt] ? `Default: ${basePrices[rt]}` : 'Enter price'}
                                                    className={`w-full pl-8 pr-3 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500
                                                        ${isOverridden ? 'border-indigo-300 bg-indigo-50' : ''}`}
                                                />
                                            </div>
                                            {isOverridden && (
                                                <p className="text-[10px] text-indigo-500 mt-0.5 ml-1">Custom price active</p>
                                            )}
                                        </div>
                                    );
                                })}
                            </div>
                        )}

                        <button
                            onClick={handleSave}
                            disabled={saving}
                            className="mt-5 w-full flex items-center justify-center gap-2 px-4 py-2.5 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors text-sm font-medium disabled:opacity-50"
                        >
                            {saving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
                            Save Prices
                        </button>

                        {Object.keys(basePrices).length > 0 && (
                            <div className="mt-4 p-3 bg-gray-50 rounded-lg border">
                                <p className="text-xs font-semibold text-gray-500 mb-2">Default Prices (base)</p>
                                {ROOM_TYPES.filter(rt => basePrices[rt] != null).map(rt => (
                                    <div key={rt} className="flex justify-between text-xs text-gray-600">
                                        <span>{rt}</span>
                                        <span className="font-medium">₹{basePrices[rt]}</span>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                ) : (
                    <div className="bg-white rounded-2xl shadow-sm border w-full lg:w-72 p-5 self-start flex flex-col items-center justify-center text-center text-gray-400 min-h-[200px]">
                        <CalendarDays size={36} className="mb-3 text-gray-300" />
                        <p className="text-sm font-medium">Click any date</p>
                        <p className="text-xs mt-1">to set custom prices for that day</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default PriceCalendar;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { lodgeAPI, API_BASE_URL } from '../../services/api';
import { UserPlus, Trash2, Edit2, X, Loader2, Users, Building2, Shield, ShieldCheck } from 'lucide-react';

const UserManagement = () => {
    const { user } = useAuth();
    const [users, setUsers] = useState([]);
    const [lodges, setLodges] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [editingUser, setEditingUser] = useState(null);
    const [saving, setSaving] = useState(false);
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: '',
        role: 'admin',
        lodgeId: ''
    });

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async (showLoading = true) => {
        try {
            if (showLoading) setLoading(true);
            // Add timestamp to prevent caching
            const [usersRes, lodgesData] = await Promise.all([
                fetch(`${API_BASE_URL}/users?t=${new Date().getTime()}`).then(r => r.json()),
                lodgeAPI.getAll()
            ]);
            console.log('Users loaded:', usersRes);
            console.log('Lodges loaded:', lodgesData);
            setUsers(usersRes.users || []);
            // Handle if lodges response is an object with lodges array
            setLodges(Array.isArray(lodgesData) ? lodgesData : (lodgesData?.lodges || []));
        } catch (error) {
            console.error('Error fetching data:', error);
        } finally {
            if (showLoading) setLoading(false);
        }
    };

    const handleOpenModal = (userToEdit = null) => {
        if (userToEdit) {
            setEditingUser(userToEdit);
            // Extract lodgeId - it might be populated object or plain string
            let lodgeIdValue = '';
            if (userToEdit.lodgeId) {
                lodgeIdValue = typeof userToEdit.lodgeId === 'object'
                    ? userToEdit.lodgeId._id
                    : userToEdit.lodgeId;
            }
            setFormData({
                name: userToEdit.name,
                email: userToEdit.email,
                password: '',
                role: userToEdit.role,
                lodgeId: lodgeIdValue
            });
        } else {
            setEditingUser(null);
            setFormData({
                name: '',
                email: '',
                password: '',
                role: 'admin',
                lodgeId: ''
            });
        }
        setShowModal(true);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setSaving(true);

        try {
            const url = editingUser
                ? `${API_BASE_URL}/users/${editingUser._id}`
                : `${API_BASE_URL}/users`;

            const method = editingUser ? 'PUT' : 'POST';

            const payload = {
                name: formData.name,
                email: formData.email,
                role: formData.role,
                lodgeId: formData.role === 'admin' ? formData.lodgeId : null
            };

            // Only include password if it's provided (for new users or password update)
            if (formData.password) {
                payload.password = formData.password;
            }

            const response = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });

            const result = await response.json();

            if (result.success) {
                // Optimistic update
                if (editingUser) {
                    // Update existing user in state
                    setUsers(users.map(u => u._id === editingUser._id ? result.user : u));
                } else {
                    // Add new user to state
                    setUsers([...users, result.user]);
                }

                // Also fetch fresh data to be sure (with cache busting)
                fetchData(false);
                setShowModal(false);
            } else {
                alert(result.message || 'Failed to save user');
            }
        } catch (error) {
            console.error('Error saving user:', error);
            alert('Error saving user');
        } finally {
            setSaving(false);
        }
    };

    const handleDelete = async (userId) => {
        if (!confirm('Are you sure you want to delete this user?')) return;

        try {
            const response = await fetch(`${API_BASE_URL}/users/${userId}`, {
                method: 'DELETE'
            });
            const result = await response.json();

            if (result.success) {
                setUsers(users.filter(u => u._id !== userId));
                fetchData(false);
            } else {
                alert(result.message || 'Failed to delete user');
            }
        } catch (error) {
            console.error('Error deleting user:', error);
            alert('Error deleting user');
        }
    };

    const getLodgeName = (user) => {
        // If lodgeId is populated (object with name), return it directly
        if (user.lodgeId && typeof user.lodgeId === 'object' && user.lodgeId.name) {
            return user.lodgeId.name;
        }
        // Otherwise, look up in lodges array
        if (!user.lodgeId) return 'Not Assigned';
        const lodgeIdStr = typeof user.lodgeId === 'object' ? user.lodgeId._id : user.lodgeId;
        const lodge = lodges.find(l => l._id === lodgeIdStr || l._id.toString() === lodgeIdStr?.toString());
        return lodge?.name || 'Not Assigned';
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="w-8 h-8 animate-spin text-indigo-500" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">
                <div>
                    <h2 className="text-2xl font-bold text-gray-900">User Management</h2>
                    <p className="text-gray-500">Manage admin users and their lodge assignments.</p>
                </div>
                <button
                    onClick={() => handleOpenModal()}
                    className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition-colors"
                >
                    <UserPlus size={18} />
                    Add New Admin
                </button>
            </div>

            {/* Users List */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">

                {/* Mobile Card View */}
                <div className="md:hidden divide-y divide-gray-100">
                    {users.map((u) => (
                        <div key={u._id} className="p-4 hover:bg-gray-50">
                            <div className="flex items-start justify-between mb-2">
                                <div className="flex items-center gap-3 flex-1 min-w-0">
                                    <div className={`w-9 h-9 rounded-full flex items-center justify-center flex-shrink-0 ${u.role === 'super_admin' ? 'bg-purple-100 text-purple-600' : 'bg-indigo-100 text-indigo-600'}`}>
                                        {u.role === 'super_admin' ? <ShieldCheck size={18} /> : <Shield size={18} />}
                                    </div>
                                    <div className="min-w-0">
                                        <div className="font-medium text-gray-900 truncate">{u.name}</div>
                                        <div className="text-xs text-gray-400 truncate">{u.email}</div>
                                    </div>
                                </div>
                                <span className={`ml-2 flex-shrink-0 px-2 py-0.5 rounded-full text-xs font-medium ${u.role === 'super_admin' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>
                                    {u.role === 'super_admin' ? 'Super Admin' : 'Lodge Admin'}
                                </span>
                            </div>
                            <div className="flex items-center justify-between mt-2">
                                <div className="text-sm text-gray-500 flex items-center gap-1">
                                    {u.role === 'super_admin' ? (
                                        <span className="italic text-gray-400">All Lodges</span>
                                    ) : (
                                        <><Building2 size={14} className="text-gray-400" /> {getLodgeName(u)}</>
                                    )}
                                </div>
                                <div className="flex items-center gap-1">
                                    <button onClick={() => handleOpenModal(u)} className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="Edit">
                                        <Edit2 size={16} />
                                    </button>
                                    {u._id !== user._id && (
                                        <button onClick={() => handleDelete(u._id)} className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors" title="Delete">
                                            <Trash2 size={16} />
                                        </button>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Desktop Table View */}
                <div className="hidden md:block overflow-x-auto">
                    <table className="w-full text-left">
                        <thead className="bg-gray-50 text-gray-600 font-medium text-sm">
                            <tr>
                                <th className="px-6 py-4">User</th>
                                <th className="px-6 py-4">Role</th>
                                <th className="px-6 py-4">Assigned Lodge</th>
                                <th className="px-6 py-4 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {users.map((u) => (
                                <tr key={u._id} className="hover:bg-gray-50 transition-colors">
                                    <td className="px-6 py-4">
                                        <div className="flex items-center gap-3">
                                            <div className={`w-10 h-10 rounded-full flex items-center justify-center ${u.role === 'super_admin' ? 'bg-purple-100 text-purple-600' : 'bg-indigo-100 text-indigo-600'
                                                }`}>
                                                {u.role === 'super_admin' ? <ShieldCheck size={20} /> : <Shield size={20} />}
                                            </div>
                                            <div>
                                                <div className="font-medium text-gray-900">{u.name}</div>
                                                <div className="text-xs text-gray-400">{u.email}</div>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className={`px-3 py-1 rounded-full text-xs font-medium ${u.role === 'super_admin'
                                            ? 'bg-purple-100 text-purple-700'
                                            : 'bg-blue-100 text-blue-700'
                                            }`}>
                                            {u.role === 'super_admin' ? 'Super Admin' : 'Lodge Admin'}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-sm text-gray-600">
                                        {u.role === 'super_admin' ? (
                                            <span className="text-gray-400 italic">All Lodges</span>
                                        ) : (
                                            <span className="flex items-center gap-2">
                                                <Building2 size={16} className="text-gray-400" />
                                                {getLodgeName(u)}
                                            </span>
                                        )}
                                    </td>
                                    <td className="px-6 py-4 text-right">
                                        <div className="flex items-center justify-end gap-2">
                                            <button
                                                onClick={() => handleOpenModal(u)}
                                                className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                                                title="Edit"
                                            >
                                                <Edit2 size={18} />
                                            </button>
                                            {u._id !== user._id && (
                                                <button
                                                    onClick={() => handleDelete(u._id)}
                                                    className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                                    title="Delete"
                                                >
                                                    <Trash2 size={18} />
                                                </button>
                                            )}
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Add/Edit Modal */}
            {showModal && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
                    <div className="bg-white rounded-xl max-w-md w-full">
                        <div className="p-6 border-b flex justify-between items-center">
                            <h3 className="text-xl font-bold">
                                {editingUser ? 'Edit Admin' : 'Add New Admin'}
                            </h3>
                            <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-100 rounded-lg">
                                <X size={20} />
                            </button>
                        </div>
                        <form onSubmit={handleSubmit} className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Full Name *</label>
                                <input
                                    type="text"
                                    value={formData.name}
                                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                    required
                                    className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Email *</label>
                                <input
                                    type="email"
                                    value={formData.email}
                                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                    required
                                    className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">
                                    Password {editingUser ? '(leave blank to keep current)' : '*'}
                                </label>
                                <input
                                    type="password"
                                    value={formData.password}
                                    onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                                    required={!editingUser}
                                    className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Role *</label>
                                <select
                                    value={formData.role}
                                    onChange={(e) => setFormData({ ...formData, role: e.target.value })}
                                    className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none bg-white"
                                >
                                    <option value="admin">Lodge Admin</option>
                                    <option value="super_admin">Super Admin</option>
                                </select>
                            </div>
                            {formData.role === 'admin' && (
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">
                                        Assign Lodge * <span className="text-xs text-gray-400">({lodges.length} lodges available)</span>
                                    </label>
                                    <select
                                        value={formData.lodgeId}
                                        onChange={(e) => setFormData({ ...formData, lodgeId: e.target.value })}
                                        required
                                        className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none bg-white"
                                    >
                                        <option value="">{lodges.length === 0 ? 'Loading lodges...' : 'Select a lodge...'}</option>
                                        {lodges.map((lodge) => (
                                            <option key={lodge._id} value={lodge._id}>
                                                {lodge.name}
                                            </option>
                                        ))}
                                    </select>
                                </div>
                            )}
                            <div className="flex gap-3 pt-4">
                                <button
                                    type="submit"
                                    disabled={saving}
                                    className="flex-1 bg-indigo-600 text-white py-2 rounded-lg font-medium hover:bg-indigo-700 disabled:opacity-50 flex items-center justify-center gap-2"
                                >
                                    {saving ? (
                                        <>
                                            <Loader2 size={18} className="animate-spin" />
                                            Saving...
                                        </>
                                    ) : (
                                        editingUser ? 'Update Admin' : 'Create Admin'
                                    )}
                                </button>
                                <button
                                    type="button"
                                    onClick={() => setShowModal(false)}
                                    className="px-4 py-2 border rounded-lg hover:bg-gray-50"
                                >
                                    Cancel
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default UserManagement;
